--

CREATE FUNCTION public.infra_get_department_id_for_settings_v4(settings_id uuid) RETURNS TABLE(department_id text)
    LANGUAGE sql STABLE
    AS $$
    SELECT ds.department_id::text
    FROM department_settings ds
    WHERE ds.settings_id = infra_get_department_id_for_settings_v4.settings_id 
      AND ds.active = true
    LIMIT 1;
$$;


--
-- Name: infra_get_settings_to_sync_v4(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.infra_get_settings_to_sync_v4() RETURNS TABLE(realm_name text)
    LANGUAGE sql STABLE
    AS $$
    -- Default settings → 'master' realm
    SELECT 'master'::text as realm_name
    WHERE EXISTS (
        SELECT 1 FROM settings s
        JOIN setting_auths sa ON sa.settings_id = s.id AND sa.active = true
        WHERE s.active = true
          AND NOT EXISTS (
              SELECT 1 FROM department_settings sd 
              WHERE sd.settings_id = s.id AND sd.active = true
          )
    )
    UNION
    -- Department-specific settings with keys → use settings_id as realm
    SELECT DISTINCT s.id::text as realm_name
    FROM settings s
    JOIN setting_auths sa ON sa.settings_id = s.id AND sa.active = true
    JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
    WHERE s.active = true
      AND EXISTS (
          SELECT 1 FROM setting_auth_keys sak
          WHERE sak.settings_id = s.id AND sak.active = true
      );
$$;


--
-- Name: infra_health_metrics_v4(text, text, boolean, double precision, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.infra_health_metrics_v4(ts text, service text, ok boolean, latency_ms double precision, error text) RETURNS TABLE(success boolean)
    LANGUAGE sql
    AS $$
    INSERT INTO service_health (ts, service, ok, latency_ms, error)
    VALUES (ts::timestamptz, service, ok, latency_ms, error)
    ON CONFLICT (ts, service) DO UPDATE
    SET ok = EXCLUDED.ok,
        latency_ms = EXCLUDED.latency_ms,
        error = EXCLUDED.error;
    SELECT true as success;
$$;


--
-- Name: infra_insert_activity_v4(text, text, uuid, boolean, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.infra_insert_activity_v4(message text, endpoint text, profile_id uuid DEFAULT NULL::uuid, error boolean DEFAULT false, session_id uuid DEFAULT NULL::uuid) RETURNS TABLE(success boolean)
    LANGUAGE sql
    AS $$
    WITH new_audit AS (
        INSERT INTO audits_entry (message, endpoint, error, session_id, created_at)
        VALUES (message, endpoint, error, session_id, now())
        RETURNING id
    ),
    link_profile AS (
        INSERT INTO profiles_audits_connection (profiles_id, audit_id)
        SELECT profile_id, na.id
        FROM new_audit na
        WHERE profile_id IS NOT NULL
    )
    SELECT true as success;
$$;


