--
-- Name: infra_resolve_from_department_profile_v4(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.infra_resolve_from_department_profile_v4(department_id text, auth_mode text) RETURNS TABLE(resolved_profile_id uuid)
    LANGUAGE sql STABLE
    AS $$
    WITH resolve_profile_from_department AS (
        SELECT 
            CASE 
                WHEN auth_mode = 'default-guest' THEN
                    COALESCE(
                        -- Try department-specific settings first (only if department_id is provided)
                        CASE 
                            WHEN department_id IS NOT NULL AND department_id != '' THEN
                                (SELECT sdg.profile_id
                                 FROM setting s
                                 JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
                                 JOIN settings_default_guest sdg ON sdg.settings_id = s.id AND sdg.active = true
                                 WHERE ds.department_id = department_id::uuid AND EXISTS (SELECT 1 FROM scenario_flags sf JOIN flags fl ON sf.flag_id = fl.id WHERE sf.scenario_id = s.id AND fl.name = 'active' AND sf.type = 'active'::type_scenario_flags AND sf.value = true)
                                 LIMIT 1)
                            ELSE NULL::uuid
                        END,
                        -- Fallback to default settings (no department links) - always try this
                        (SELECT sdg.profile_id
                         FROM setting s
                         JOIN settings_default_guest sdg ON sdg.settings_id = s.id AND sdg.active = true
                         WHERE EXISTS (SELECT 1 FROM scenario_flags sf JOIN flags fl ON sf.flag_id = fl.id WHERE sf.scenario_id = s.id AND fl.name = 'active' AND sf.type = 'active'::type_scenario_flags AND sf.value = true)
                           AND NOT EXISTS (
                               SELECT 1 FROM department_settings ds 
                               WHERE ds.settings_id = s.id AND ds.active = true
                           )
                         LIMIT 1)
                    )
                WHEN auth_mode = 'default-account' THEN
                    COALESCE(
                        -- Try department-specific settings first (only if department_id is provided)
                        CASE 
                            WHEN department_id IS NOT NULL AND department_id != '' THEN
                                (SELECT sda.profile_id
                                 FROM setting s
                                 JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
                                 JOIN settings_default_account sda ON sda.settings_id = s.id AND sda.active = true
                                 WHERE ds.department_id = department_id::uuid AND EXISTS (SELECT 1 FROM scenario_flags sf JOIN flags fl ON sf.flag_id = fl.id WHERE sf.scenario_id = s.id AND fl.name = 'active' AND sf.type = 'active'::type_scenario_flags AND sf.value = true)
                                 LIMIT 1)
                            ELSE NULL::uuid
                        END,
                        -- Fallback to default settings (no department links) - always try this
                        (SELECT sda.profile_id
                         FROM setting s
                         JOIN settings_default_account sda ON sda.settings_id = s.id AND sda.active = true
                         WHERE EXISTS (SELECT 1 FROM scenario_flags sf JOIN flags fl ON sf.flag_id = fl.id WHERE sf.scenario_id = s.id AND fl.name = 'active' AND sf.type = 'active'::type_scenario_flags AND sf.value = true)
                           AND NOT EXISTS (
                               SELECT 1 FROM department_settings ds 
                               WHERE ds.settings_id = s.id AND ds.active = true
                           )
                         LIMIT 1)
                    )
            END as resolved_profile_id
    )
    SELECT resolved_profile_id FROM resolve_profile_from_department
    WHERE resolved_profile_id IS NOT NULL;
$$;


--
-- Name: infra_snapshot_metrics_v4(text, integer, integer, double precision, double precision, bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.infra_snapshot_metrics_v4(ts text, requests_total integer, errors_total integer, avg_latency_ms double precision, cpu_percent double precision, memory_bytes bigint) RETURNS TABLE(success boolean)
    LANGUAGE sql
    AS $$
    INSERT INTO app_metrics (ts, requests_total, errors_total, avg_latency_ms, cpu_percent, memory_bytes)
    VALUES (ts::timestamptz, requests_total, errors_total, avg_latency_ms, cpu_percent, memory_bytes)
    ON CONFLICT (ts) DO UPDATE
    SET requests_total = EXCLUDED.requests_total,
        errors_total = EXCLUDED.errors_total,
        avg_latency_ms = EXCLUDED.avg_latency_ms,
        cpu_percent = EXCLUDED.cpu_percent,
        memory_bytes = EXCLUDED.memory_bytes;
    SELECT true as success;
$$;


--
-- Name: infra_update_master_realm_ssl_v4(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.infra_update_master_realm_ssl_v4() RETURNS TABLE(success boolean, message text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE keycloak.realm 
    SET ssl_required = 'NONE' 
    WHERE name = 'master';
    
    RETURN QUERY SELECT 
        true as success,
        'Master realm SSL requirement set to NONE' as message;
END;
$$;


