CREATE FUNCTION public.socket_create_feedback_v4(grade_id uuid, standard_id uuid, total integer, feedback text) RETURNS TABLE(id text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    feedback_id_val uuid;
BEGIN
    -- Create feedback record
    INSERT INTO feedbacks 
    (standard_id, total, feedback, created_at)
    VALUES (standard_id, total, feedback, NOW())
    RETURNING id INTO feedback_id_val;
    
    -- Link to grade via junction table
    INSERT INTO grade_feedbacks (grade_id, feedback_id, created_at)
    VALUES (grade_id, feedback_id_val, NOW())
    ON CONFLICT (grade_id, feedback_id) DO NOTHING;
    
    -- Return feedback id
    RETURN QUERY SELECT feedback_id_val::text;
END;
$$;


--
-- Name: socket_create_grade_v4(uuid, uuid, text, boolean, integer, integer, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_create_grade_v4(run_id uuid, rubric_grade_agent_id uuid, description text, passed boolean, score integer, time_taken integer, conversation_name text DEFAULT NULL::text, conversation_description text DEFAULT NULL::text) RETURNS TABLE(id text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_grade_id uuid;
    v_conversation_id uuid;
    v_time_id uuid;
    v_chat_title text;
    v_final_conversation_name text;
    v_final_conversation_description text;
    v_end_reason text;
BEGIN
    -- Get chat title if run is linked to a chat
    SELECT (SELECT n.name FROM cohort_names cn JOIN names n ON cn.name_id = n.id WHERE cn.cohort_id = c.id LIMIT 1) INTO v_chat_title
    FROM chat_runs cr
    JOIN chat c ON c.id = cr.chat_id
    WHERE cr.run_id = run_id
    LIMIT 1;
    
    -- Determine conversation name and description
    v_final_conversation_name := COALESCE(conversation_name, v_chat_title, description, 'Conversation');
    v_final_conversation_description := COALESCE(conversation_description, description);
    v_end_reason := CASE
        WHEN v_final_conversation_description IS NULL OR v_final_conversation_description = '' THEN v_final_conversation_name
        WHEN v_final_conversation_name IS NULL OR v_final_conversation_name = '' THEN v_final_conversation_description
        ELSE v_final_conversation_name || ': ' || v_final_conversation_description
    END;
    
    -- Create conversation
    INSERT INTO conversations (end_reason, created_at, updated_at)
    VALUES (v_end_reason, NOW(), NOW())
    RETURNING id INTO v_conversation_id;
    
    -- Create time record if time_taken is provided
    IF time_taken IS NOT NULL AND time_taken > 0 THEN
        INSERT INTO times (time_taken, active, created_at, updated_at)
        VALUES (time_taken, TRUE, NOW(), NOW())
        ON CONFLICT DO NOTHING
        RETURNING id INTO v_time_id;
        
        -- Get existing time if conflict occurred
        IF v_time_id IS NULL THEN
            SELECT id INTO v_time_id FROM times WHERE time_taken = time_taken AND active = TRUE LIMIT 1;
        END IF;
    END IF;
    
    -- Create grade
    INSERT INTO grade (run_id, rubric_grade_agent_id, description, passed, score, created_at)
    VALUES (run_id, rubric_grade_agent_id, description, passed, score, NOW())
    RETURNING id INTO v_grade_id;
    
    -- Link grade to conversation
    INSERT INTO grade_conversations (grade_id, conversation_id, created_at, updated_at)
    VALUES (v_grade_id, v_conversation_id, NOW(), NOW())
    ON CONFLICT (grade_id, conversation_id) DO NOTHING;
    
    -- Link grade to time if time was created
    IF v_time_id IS NOT NULL THEN
        INSERT INTO grade_times (grade_id, time_id, active, created_at, updated_at)
        VALUES (v_grade_id, v_time_id, TRUE, NOW(), NOW())
        ON CONFLICT (grade_id, time_id) DO NOTHING;
    END IF;
    
    -- Return grade id
    RETURN QUERY SELECT v_grade_id::text;
END $$;


--
-- Name: socket_create_hints_v4(uuid, text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_create_hints_v4(message_id uuid, hint_texts text[]) RETURNS TABLE(hints types.i_create_hints_v4_hint_result[])
    LANGUAGE sql
    AS $$
WITH hint_texts_array AS (
    SELECT 
        t.hint_text,
        t.idx
    FROM unnest(hint_texts) WITH ORDINALITY AS t(hint_text, idx)
    WHERE trim(t.hint_text) != ''
),
hints_with_next_idx AS (
    SELECT 
        hta.hint_text,
        hta.idx as original_idx,
        COALESCE(
            (SELECT MAX(mh.idx) FROM message_hints mh WHERE mh.message_id = message_id),
            -1
        ) + ROW_NUMBER() OVER (ORDER BY hta.idx) as next_idx
    FROM hint_texts_array hta
),
inserted_hint_entities AS (
    INSERT INTO hints (hint, created_at, updated_at)
    SELECT DISTINCT
        hwni.hint_text,
        NOW(),
        NOW()
    FROM hints_with_next_idx hwni
    ON CONFLICT DO NOTHING
    RETURNING id, hint
),
inserted_hints AS (
    INSERT INTO message_hints (message_id, hint_id, idx, created_at, updated_at)
    SELECT 
        message_id,
        ihe.id,
        hwni.next_idx,
        NOW(),
        NOW()
    FROM hints_with_next_idx hwni
    JOIN inserted_hint_entities ihe ON ihe.hint = hwni.hint_text
    RETURNING message_id, idx, (SELECT hint FROM hints WHERE id = hint_id) as hint
)
SELECT 
    COALESCE(
        ARRAY_AGG(
            (message_id, idx, hint)::types.i_create_hints_v4_hint_result
            ORDER BY idx
        ),
        '{}'::types.i_create_hints_v4_hint_result[]
    ) as hints
FROM inserted_hints
$$;


