--
-- Name: socket_create_model_run_v4(uuid, uuid, uuid, text, uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_create_model_run_v4(department_id uuid, model_id uuid, entity_id uuid, entity_type text, profile_id uuid DEFAULT NULL::uuid, key_id uuid DEFAULT NULL::uuid, agent_id uuid DEFAULT NULL::uuid) RETURNS TABLE(run_id text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        department_id AS department_id,
        model_id AS model_id,
        entity_id AS entity_id,
        entity_type AS entity_type,
        profile_id AS profile_id,
        key_id AS key_id,
        agent_id AS agent_id
),
create_run AS (
    -- 1. Create run record with key_id and agent_id if provided
    INSERT INTO run (input_tokens, output_tokens, key_id, agent_id)
    SELECT 0, 0, p.key_id, p.agent_id
    FROM params p
    RETURNING id
),
link_model AS (
    -- 2. Link model to run
    INSERT INTO run_models (run_id, model_id, active)
    SELECT cr.id, p.model_id, true
    FROM create_run cr
    CROSS JOIN params p
    RETURNING run_id
),
link_persona AS (
    -- 3. Link persona to run (only if entity_type is 'persona')
    INSERT INTO run_personas (run_id, persona_id, active)
    SELECT lm.run_id, p.entity_id, true
    FROM link_model lm
    CROSS JOIN params p
    WHERE p.entity_type = 'persona'
    RETURNING run_id
),
link_profile AS (
    -- 4. Link profile to run if provided (conditional)
    INSERT INTO run_profiles (run_id, profile_id, active)
    SELECT lm.run_id, p.profile_id, true
    FROM link_model lm
    CROSS JOIN params p
    WHERE p.profile_id IS NOT NULL
    RETURNING run_id
)
SELECT id::text as run_id
FROM create_run
$$;


--
-- Name: socket_create_template_and_link_v4(uuid, uuid, text, uuid, boolean, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_create_template_and_link_v4(document_id uuid, html_id uuid, name text, schema_id uuid, active boolean, run_id uuid) RETURNS TABLE(template_id uuid)
    LANGUAGE sql
    AS $_$
WITH deactivate_previous AS (
    -- Mark all previous templates as inactive if new one is active
    UPDATE document_templates
    SET active = false, updated_at = NOW()
    WHERE document_templates.document_id = $1
      AND document_templates.active = true
      AND $5 = true
),
existing_template AS (
    -- Check if template already exists (same html_id and schema_id via document_html and document_schemas)
    SELECT DISTINCT dt.template_id
    FROM document_templates dt
    JOIN document_html dh ON dh.document_id = dt.document_id AND dh.html_id = $2 AND dh.active = true
    JOIN document_schemas ds ON ds.document_id = dt.document_id AND ds.schema_id = $4 AND ds.active = true
    WHERE dt.active = true
    LIMIT 1
),
create_template AS (
    -- Create template (just values, no schema/HTML refs)
    INSERT INTO templates (name, created_at, updated_at)
    SELECT 
        $3,
        NOW(),
        NOW()
    WHERE NOT EXISTS (SELECT 1 FROM existing_template)
    RETURNING templates.id as template_id
),
template_id AS (
    SELECT template_id FROM existing_template
    UNION ALL
    SELECT template_id FROM create_template
    LIMIT 1
),
link_schema AS (
    -- Link template to schema via schema_templates junction table
    INSERT INTO schema_templates (schema_id, template_id, created_at, updated_at)
    SELECT 
        $4,
        ti.template_id,
        NOW(),
        NOW()
    FROM template_id ti
    WHERE $4 IS NOT NULL
    ON CONFLICT (schema_id, template_id) DO UPDATE SET
        updated_at = NOW()
),
link_to_document AS (
    -- Link template to document (without html_id and schema_id)
    INSERT INTO document_templates (document_id, template_id, active, created_at, updated_at)
    SELECT 
        $1,
        ti.template_id,
        $5,
        NOW(),
        NOW()
    FROM template_id ti
    ON CONFLICT (document_id, template_id) DO UPDATE SET
        active = EXCLUDED.active,
        updated_at = NOW()
    RETURNING template_id
),
link_html_to_document AS (
    -- Link HTML to document via document_html junction
    INSERT INTO document_html (document_id, html_id, active, created_at, updated_at)
    SELECT 
        $1,
        $2,
        $5,
        NOW(),
        NOW()
    FROM template_id ti
    WHERE $2 IS NOT NULL
    ON CONFLICT (document_id, html_id) DO UPDATE SET
        active = EXCLUDED.active,
        updated_at = NOW()
),
link_schema_to_document AS (
    -- Link schema to document via document_schemas junction
    INSERT INTO document_schemas (document_id, schema_id, active, created_at, updated_at)
    SELECT 
        $1,
        $4,
        $5,
        NOW(),
        NOW()
    FROM template_id ti
    WHERE $4 IS NOT NULL
    ON CONFLICT (document_id, schema_id) DO UPDATE SET
        active = EXCLUDED.active,
        updated_at = NOW()
),
link_to_run AS (
    -- Link template to run via tool_call if run_id provided
    -- Note: Templates no longer have tool_call_id, so we can't verify the run relationship
    -- This CTE is kept for compatibility but doesn't perform verification
    SELECT 
        ltd.template_id
    FROM link_to_document ltd
    WHERE $6 IS NOT NULL
)
SELECT template_id FROM link_to_document LIMIT 1
$_$;


