--
-- Name: socket_document_debug_eval_start_v4(uuid, uuid, uuid, uuid, uuid, uuid, uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_document_debug_eval_start_v4(profile_id uuid, test_id uuid, attempt_id uuid, eval_id uuid, tool_id uuid, run_id uuid DEFAULT NULL::uuid, group_id uuid DEFAULT NULL::uuid, use_groups boolean DEFAULT false) RETURNS TABLE(test_id text, attempt_id text, eval_id text, run_id text, group_id text, tool_id text, success boolean, message text)
    LANGUAGE sql
    AS $$
-- No-op: Just returns eval info (no database operations)
SELECT 
    test_id::text as test_id,
    attempt_id::text as attempt_id,
    eval_id::text as eval_id,
    run_id::text as run_id,
    group_id::text as group_id,
    tool_id::text as tool_id,
    true as success,
    'Debug eval started' as message
$$;


