--

CREATE FUNCTION public.socket_link_attempt_test_v4(attempt_id uuid, test_id uuid) RETURNS void
    LANGUAGE sql
    AS $_$
    INSERT INTO attempt_tests (attempt_id, test_id)
    VALUES ($1, $2)
    ON CONFLICT DO NOTHING
$_$;


--
-- Name: socket_mark_chat_completed_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_mark_chat_completed_v4(chat_id uuid) RETURNS TABLE(success boolean)
    LANGUAGE sql
    AS $$
    UPDATE chat
    SET completed = true,
        updated_at = NOW()
    WHERE id = chat_id
    RETURNING true as success
$$;


--
-- Name: socket_mark_eval_group_complete_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_mark_eval_group_complete_v4(eval_id uuid, group_id uuid) RETURNS void
    LANGUAGE sql
    AS $_$
    -- Note: eval_groups table doesn't have completed column
    -- Completion is tracked via eval_runs.completed
    UPDATE eval_groups SET updated_at = NOW()
    WHERE eval_groups.eval_id = $1 AND eval_groups.group_id = $2
$_$;


--
-- Name: socket_mark_eval_run_complete_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_mark_eval_run_complete_v4(eval_id uuid, run_id uuid) RETURNS void
    LANGUAGE sql
    AS $_$
    UPDATE eval_runs SET completed = true, updated_at = NOW()
    WHERE eval_runs.eval_id = $1 AND eval_runs.run_id = $2
$_$;


--
-- Name: socket_mark_test_complete_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_mark_test_complete_v4(test_id uuid) RETURNS void
    LANGUAGE sql
    AS $_$
    UPDATE tests SET completed = true, updated_at = NOW() WHERE tests.id = $1
$_$;


