--
-- Name: socket_member_progress_upsert_v4(uuid, text, boolean, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_member_progress_upsert_v4(chat_id uuid, message_contents text, audio boolean, upload_id uuid DEFAULT NULL::uuid) RETURNS TABLE(message_id text, run_id text, audio boolean, chat_id text, group_id text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT chat_id, message_contents, audio, upload_id
),
-- Get member agent (role='member')
member_agent AS (
    SELECT a.id as agent_id
    FROM agent a
    JOIN agent_domains adom ON adom.agent_id = a.id
    JOIN domain_artifacts da ON da.domain_id = adom.domain_id AND da.artifact = CAST('agent' AS artifacts)
    WHERE EXISTS (SELECT 1 FROM agent_flags af JOIN flags fl ON af.flag_id = fl.id WHERE af.agent_id = a.id AND fl.name = 'active' AND af.type = 'active'::type_agent_flags AND af.value = true)
    LIMIT 1
),
-- Get chat context
chat_context AS (
    SELECT 
        c.id as chat_id,
        (SELECT n.name FROM cohort_names cn JOIN names n ON cn.name_id = n.id WHERE cn.cohort_id = c.id LIMIT 1) as chat_title,
        c.scenario_id,
        g.trace_id,
        sa.id as attempt_id,
        sa.simulation_id,
        ap.profile_id
    FROM params p
    JOIN chat c ON c.id = p.chat_id
    JOIN attempt_chats ac ON ac.chat_id = c.id
    JOIN simulation_attempts sa ON sa.id = ac.attempt_id
    LEFT JOIN groups g ON g.id = (SELECT cg.group_id FROM chat_groups cg WHERE cg.chat_id = c.id LIMIT 1)
    LEFT JOIN attempt_profiles ap ON ap.attempt_id = sa.id AND ap.active = true
    LIMIT 1
),
-- Get or create group for chat
chat_group AS (
    SELECT cg.group_id
    FROM params p
    JOIN chat_groups cg ON cg.chat_id = p.chat_id
    LIMIT 1
),
create_group_if_needed AS (
    INSERT INTO groups (created_at, updated_at)
    SELECT NOW(), NOW()
    FROM params p
    WHERE NOT EXISTS (SELECT 1 FROM chat_group)
    RETURNING id AS group_id
),
create_chat_group_if_needed AS (
    INSERT INTO chat_groups (chat_id, group_id, created_at, updated_at)
    SELECT p.chat_id, cg.group_id, NOW(), NOW()
    FROM params p
    CROSS JOIN create_group_if_needed cg
    WHERE NOT EXISTS (SELECT 1 FROM chat_group)
    ON CONFLICT (chat_id, group_id) DO NOTHING
    RETURNING group_id
),
selected_group AS (
    SELECT group_id FROM chat_group
    UNION ALL
    SELECT group_id FROM create_group_if_needed
    UNION ALL
    SELECT group_id FROM create_chat_group_if_needed
),
target_group AS (
    SELECT group_id
    FROM selected_group
    LIMIT 1
),
-- Get latest run for this chat (if exists)
latest_run AS (
    SELECT r.id as run_id
    FROM params p
    JOIN target_group tg ON true
    JOIN group_runs gr ON gr.group_id = tg.group_id
    JOIN run r ON r.id = gr.run_id
    JOIN run_profiles rp ON rp.run_id = r.id AND rp.active = true
    JOIN chat_context cc ON cc.profile_id = rp.profile_id
    WHERE r.agent_id = (SELECT agent_id FROM member_agent)
    ORDER BY r.created_at DESC
    LIMIT 1
),
-- Upsert run (create if doesn't exist)
create_run_if_needed AS (
    INSERT INTO run (input_tokens, output_tokens, key_id, agent_id)
    SELECT 0, 0, NULL, ma.agent_id
    FROM member_agent ma
    WHERE NOT EXISTS (SELECT 1 FROM latest_run)
    RETURNING id as run_id
),
upserted_run AS (
    SELECT run_id FROM latest_run
    UNION ALL
    SELECT run_id FROM create_run_if_needed
),
-- Link run to group (atomic)
link_run_to_group AS (
    INSERT INTO group_runs (group_id, run_id, idx, created_at, updated_at)
    SELECT
        tg.group_id,
        ur.run_id,
        COALESCE(
            (SELECT MAX(idx) FROM group_runs WHERE group_id = tg.group_id),
            -1
        ) + 1,
        NOW(),
        NOW()
    FROM target_group tg
    CROSS JOIN upserted_run ur
    ON CONFLICT (group_id, run_id) DO NOTHING
    RETURNING run_id
),
-- Link profile to run (if not already linked)
link_profile_to_run AS (
    INSERT INTO run_profiles (run_id, profile_id, active)
    SELECT ur.run_id, cc.profile_id, true
    FROM upserted_run ur
    CROSS JOIN chat_context cc
    WHERE cc.profile_id IS NOT NULL
      AND NOT EXISTS (
          SELECT 1 FROM run_profiles rp 
          WHERE rp.run_id = ur.run_id 
          AND rp.profile_id = cc.profile_id 
          AND rp.active = true
      )
    RETURNING run_id
),
-- Get speak tool_id for member agent
get_speak_tool_id AS (
    SELECT t.id as tool_id
    FROM tool t
    INNER JOIN resource_tools rt ON rt.tool_id = t.id AND rt.resource = CAST('content' AS resources)
    WHERE t.name = 'speak' AND t.active = true
    LIMIT 1
),
-- Get latest user message for this run (if exists, for upsert)
latest_user_message AS (
    SELECT m.id as message_id
    FROM upserted_run ur
    JOIN message_runs mr ON mr.run_id = ur.run_id
    JOIN message m ON m.id = mr.message_id
    WHERE m.role = 'user'::message_role
    ORDER BY m.created_at DESC
    LIMIT 1
),
-- Upsert user message (create if empty, update if exists)
create_message_if_needed AS (
    INSERT INTO message (role, completed, audio, created_at, updated_at)
    SELECT 'user'::message_role, true, p.audio, NOW(), NOW()
    FROM params p
    WHERE NOT EXISTS (SELECT 1 FROM latest_user_message)
    RETURNING id as message_id, created_at, updated_at
),
-- Create synthetic tool call for new user messages
user_tool_call AS (
    INSERT INTO calls (external_call_id, tool_id, template_id, arguments_raw, completed, created_at, updated_at)
    SELECT 
        'member_progress_user_' || cm.message_id::text, 
        gst.tool_id, 
        (SELECT template_id FROM tool_templates WHERE tool_id = gst.tool_id LIMIT 1),
        '',
        true, 
        cm.created_at, 
        cm.updated_at
    FROM create_message_if_needed cm
    CROSS JOIN get_speak_tool_id gst
    CROSS JOIN upserted_run ur
    WHERE NOT EXISTS (SELECT 1 FROM latest_user_message)
    RETURNING id as tool_call_id, created_at, updated_at
),
link_user_tool_call_to_message AS (
    INSERT INTO message_calls (message_id, call_id, created_at, updated_at)
    SELECT 
        cm.message_id,
        utc.tool_call_id,
        NOW(),
        NOW()
    FROM create_message_if_needed cm
    CROSS JOIN user_tool_call utc
    WHERE NOT EXISTS (SELECT 1 FROM latest_user_message)
    ON CONFLICT (message_id, call_id) DO NOTHING
),
-- Get existing tool_call_id for existing user messages (via message_runs -> calls)
existing_user_tool_call AS (
    SELECT DISTINCT tc.id as tool_call_id
    FROM latest_user_message lum
    JOIN message_contents mc ON mc.message_id = lum.message_id AND mc.idx = 0
    JOIN message_runs mr ON mr.message_id = lum.message_id
    JOIN message_calls mcc ON mcc.message_id = lum.message_id
    JOIN calls tc ON tc.id = mcc.call_id
    LIMIT 1
),
-- Combine new and existing tool calls
user_tool_call_id AS (
    SELECT tool_call_id FROM user_tool_call
    UNION ALL
    SELECT tool_call_id FROM existing_user_tool_call
),
insert_user_content_if_needed AS (
    INSERT INTO contents (content, created_at, updated_at)
    SELECT p.message_contents, cm.created_at, cm.updated_at
    FROM create_message_if_needed cm
    CROSS JOIN params p
    CROSS JOIN user_tool_call_id utc
    WHERE NOT EXISTS (SELECT 1 FROM latest_user_message)
    RETURNING id as content_id, created_at, updated_at
),
update_message_content_if_needed AS (
    INSERT INTO message_contents (message_id, content_id, idx, created_at, updated_at)
    SELECT cm.message_id, ic.content_id, 0, ic.created_at, ic.updated_at
    FROM create_message_if_needed cm
    CROSS JOIN params p
    CROSS JOIN user_tool_call_id utc
    CROSS JOIN insert_user_content_if_needed ic
    WHERE NOT EXISTS (SELECT 1 FROM latest_user_message)
),
update_existing_message AS (
    UPDATE message
    SET audio = p.audio,
        updated_at = NOW()
    FROM params p
    WHERE id = (SELECT message_id FROM latest_user_message)
      AND EXISTS (SELECT 1 FROM latest_user_message)
    RETURNING id as message_id
),
update_existing_message_content AS (
    UPDATE contents
    SET content = p.message_contents,
        updated_at = NOW()
    FROM params p,
         message_contents mc
    WHERE mc.content_id = contents.id
      AND mc.message_id = (SELECT message_id FROM latest_user_message)
      AND mc.idx = 0
      AND EXISTS (SELECT 1 FROM latest_user_message)
),
upserted_message AS (
    SELECT message_id FROM create_message_if_needed
    UNION ALL
    SELECT message_id FROM update_existing_message
),
-- Link message to run
link_message_to_run AS (
    INSERT INTO message_runs (message_id, run_id, created_at, updated_at)
    SELECT um.message_id, ur.run_id, NOW(), NOW()
    FROM upserted_message um
    CROSS JOIN upserted_run ur
    ON CONFLICT (message_id, run_id) DO UPDATE SET updated_at = NOW()
    RETURNING message_id, run_id
),
-- Create audio record and link to upload if upload_id provided
create_audio_if_provided AS (
    INSERT INTO audios (created_at, updated_at, active, generated, call_id)
    SELECT NOW(), NOW(), true, false, NULL
    FROM params p
    WHERE p.upload_id IS NOT NULL
    RETURNING id as audio_id
),
link_audio_upload_if_provided AS (
    INSERT INTO audio_uploads (audio_id, upload_id, active, created_at, updated_at)
    SELECT ca.audio_id, p.upload_id, true, NOW(), NOW()
    FROM create_audio_if_provided ca
    CROSS JOIN params p
    WHERE p.upload_id IS NOT NULL
),
link_audio_to_message_if_provided AS (
    INSERT INTO message_audios (message_id, audio_id, created_at, updated_at)
    SELECT um.message_id, ca.audio_id, NOW(), NOW()
    FROM upserted_message um
    CROSS JOIN create_audio_if_provided ca
    CROSS JOIN params p
    WHERE p.upload_id IS NOT NULL
    ON CONFLICT (message_id, upload_id) DO UPDATE SET updated_at = NOW()
),
-- Create branch from latest message (if exists)
latest_message_for_branch AS (
    SELECT m.id as parent_id
    FROM params p
    JOIN chat_groups cg ON cg.chat_id = p.chat_id
    JOIN groups g ON g.id = cg.group_id
    JOIN group_runs gr ON gr.group_id = g.id
    JOIN run r ON r.id = gr.run_id
    JOIN message_runs mr ON mr.run_id = r.id
    JOIN message m ON m.id = mr.message_id
    WHERE m.role IN ('user'::message_role, 'assistant'::message_role, 'system'::message_role, 'developer'::message_role)
    ORDER BY m.created_at DESC
    LIMIT 1
),
create_branch AS (
    INSERT INTO message_tree (parent_id, child_id, active, created_at, updated_at)
    SELECT 
        lmb.parent_id,
        um.message_id as child_id,
        true,
        NOW(),
        NOW()
    FROM upserted_message um
    CROSS JOIN latest_message_for_branch lmb
    WHERE lmb.parent_id IS NOT NULL
      AND lmb.parent_id != um.message_id  -- Prevent self-references
      AND NOT EXISTS (
          SELECT 1 FROM message_tree mt 
          WHERE mt.parent_id = lmb.parent_id 
          AND mt.child_id = um.message_id 
          AND mt.active = true
      )
    ON CONFLICT (parent_id, child_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
-- Get department_id for linking system/developer messages
resolved_dept AS (
    SELECT COALESCE(
        (SELECT sd.department_id FROM chat_context cc
         JOIN scenario_departments sd ON sd.scenario_id = cc.scenario_id AND sd.active = true LIMIT 1),
        (SELECT pd.department_id FROM chat_context cc
         JOIN profile_departments pd ON pd.profile_id = cc.profile_id AND pd.active = true LIMIT 1),
        (SELECT id FROM department d WHERE EXISTS (SELECT 1 FROM department_flags df JOIN flags fl ON df.flag_id = fl.id WHERE df.department_id = d.id AND fl.name = 'active' AND df.type = 'active'::type_department_flags AND df.value = TRUE) LIMIT 1)
    ) as department_id
),
-- Link system/developer messages to run (reuse logic from link_system_developer_messages_to_run.sql)
run_info AS (
    SELECT 
        ur.run_id,
        ur.run_id as agent_id,  -- Will be resolved from run.agent_id below
        (SELECT rp.persona_id FROM run_personas rp WHERE rp.run_id = ur.run_id AND rp.active = true LIMIT 1) as persona_id,
        (SELECT department_id FROM resolved_dept) as department_id
    FROM upserted_run ur
),
persona_system_prompt AS (
    SELECT 
        CASE 
            WHEN pi_inst.template IS NOT NULL AND pi_inst.template != '' THEN
                COALESCE(pr_dept.system_prompt, pr_default.system_prompt) || E'\n\n' || pi_inst.template
            ELSE
                COALESCE(pr_dept.system_prompt, pr_default.system_prompt)
        END as system_prompt
    FROM run_info ri
    JOIN run_personas rp ON rp.run_id = ri.run_id AND rp.active = true
    JOIN personas p ON p.id = rp.persona_id
    LEFT JOIN persona_instructions pi ON pi.persona_id = p.id
    LEFT JOIN instructions pi_inst ON pi_inst.id = pi.instruction_id
    JOIN run r ON r.id = ri.run_id
    JOIN agents a ON a.id = r.agent_id
    LEFT JOIN agent_department_prompts adp ON adp.agent_id = a.id 
        AND adp.department_id = ri.department_id
        AND adp.active = true
    LEFT JOIN prompts pr_dept ON pr_dept.id = adp.prompt_id
    LEFT JOIN agent_prompts ap ON ap.agent_id = a.id AND ap.active = true
    LEFT JOIN prompts pr_default ON pr_default.id = ap.prompt_id
    WHERE ri.persona_id IS NOT NULL
    AND COALESCE(pr_dept.system_prompt, pr_default.system_prompt) IS NOT NULL
    AND COALESCE(pr_dept.system_prompt, pr_default.system_prompt) != ''
),
agent_system_prompt AS (
    SELECT 
        COALESCE(pr_dept.system_prompt, pr_default.system_prompt) as system_prompt
    FROM run_info ri
    JOIN run r ON r.id = ri.run_id
    JOIN agents a ON a.id = r.agent_id
    LEFT JOIN agent_department_prompts adp ON adp.agent_id = a.id 
        AND adp.department_id = ri.department_id
        AND adp.active = true
    LEFT JOIN prompts pr_dept ON pr_dept.id = adp.prompt_id
    LEFT JOIN agent_prompts ap ON ap.agent_id = a.id AND ap.active = true
    LEFT JOIN prompts pr_default ON pr_default.id = ap.prompt_id
    WHERE ri.agent_id IS NOT NULL
    AND ri.persona_id IS NULL
    AND COALESCE(pr_dept.system_prompt, pr_default.system_prompt) IS NOT NULL
    AND COALESCE(pr_dept.system_prompt, pr_default.system_prompt) != ''
),
system_message_content AS (
    SELECT system_prompt as content FROM persona_system_prompt
    UNION ALL
    SELECT system_prompt as content FROM agent_system_prompt
),
system_message_hash AS (
    SELECT DISTINCT message_content_hash(smc.content, 'system') as hash, smc.content
    FROM system_message_content smc
),
existing_system_message AS (
    SELECT m.id as system_message_id
    FROM message m
    JOIN message_contents mc ON mc.message_id = m.id AND mc.idx = 0
        JOIN contents cnt ON cnt.id = mc.content_id
    JOIN system_message_hash smh ON message_content_hash(cnt.content, 'system') = smh.hash
    WHERE m.role = 'system'::message_role
    LIMIT 1
),
new_system_message AS (
    INSERT INTO message (role, completed, audio, created_at, updated_at)
    SELECT 'system'::message_role, false, false, NOW(), NOW()
    FROM system_message_content smc
    WHERE NOT EXISTS (SELECT 1 FROM existing_system_message)
    RETURNING id as system_message_id, created_at, updated_at
),
-- Insert system message content (no tool_call_id - prompt tool moved to prompt agent)
insert_system_content_step1 AS (
    INSERT INTO contents (content, created_at, updated_at)
    SELECT smc.content, nsm.created_at, nsm.updated_at
    FROM new_system_message nsm
    CROSS JOIN system_message_content smc
    WHERE NOT EXISTS (SELECT 1 FROM existing_system_message)
    RETURNING id as content_id, created_at, updated_at
),
insert_system_content AS (
    INSERT INTO message_contents (message_id, content_id, idx, created_at, updated_at)
    SELECT nsm.system_message_id, ic.content_id, 0, ic.created_at, ic.updated_at
    FROM new_system_message nsm
    CROSS JOIN system_message_content smc
    CROSS JOIN insert_system_content_step1 ic
    WHERE NOT EXISTS (SELECT 1 FROM existing_system_message)
),
system_message AS (
    SELECT system_message_id FROM existing_system_message
    UNION ALL
    SELECT system_message_id FROM new_system_message
),
link_system AS (
    INSERT INTO message_runs (message_id, run_id, created_at, updated_at)
    SELECT sm.system_message_id, ur.run_id, NOW(), NOW()
    FROM system_message sm
    CROSS JOIN upserted_run ur
    ON CONFLICT (message_id, run_id) DO UPDATE SET updated_at = NOW()
    RETURNING message_id as system_message_id
),
scenario_developer_content AS (
    SELECT DISTINCT
        'The following is the scenario for the chat: ' || ps.problem_statement as content
    FROM run_info ri
    JOIN upserted_run ur ON ur.run_id = ri.run_id
    JOIN target_group tg ON true
    JOIN chat_groups cg ON cg.group_id = tg.group_id
    JOIN chat c ON c.id = cg.chat_id
    JOIN scenario_problem_statements sps ON sps.scenario_id = c.scenario_id AND sps.active = true
    JOIN problem_statements ps ON ps.id = sps.problem_statement_id
    WHERE ps.problem_statement IS NOT NULL 
    AND ps.problem_statement != ''
),
scenario_developer_hash AS (
    SELECT DISTINCT message_content_hash(sdc.content, 'developer') as hash, sdc.content
    FROM scenario_developer_content sdc
),
existing_scenario_developer_message AS (
    SELECT m.id as developer_message_id
    FROM message m
    JOIN message_contents mc ON mc.message_id = m.id AND mc.idx = 0
        JOIN contents cnt ON cnt.id = mc.content_id
    JOIN scenario_developer_hash sdh ON message_content_hash(cnt.content, 'developer') = sdh.hash
    WHERE m.role = 'developer'::message_role
    LIMIT 1
),
new_scenario_developer_message AS (
    INSERT INTO message (role, completed, audio, created_at, updated_at)
    SELECT 'developer'::message_role, false, false, NOW(), NOW()
    FROM scenario_developer_content sdc
    WHERE NOT EXISTS (SELECT 1 FROM existing_scenario_developer_message)
    RETURNING id as developer_message_id, created_at, updated_at
),
-- Insert developer message content (no tool_call_id - instruct tool moved to prompt agent)
insert_scenario_developer_content_step1 AS (
    INSERT INTO contents (content, created_at, updated_at)
    SELECT sdc.content, nsdm.created_at, nsdm.updated_at
    FROM new_scenario_developer_message nsdm
    CROSS JOIN scenario_developer_content sdc
    WHERE NOT EXISTS (SELECT 1 FROM existing_scenario_developer_message)
    RETURNING id as content_id, created_at, updated_at
),
insert_scenario_developer_content AS (
    INSERT INTO message_contents (message_id, content_id, idx, created_at, updated_at)
    SELECT nsdm.developer_message_id, ic.content_id, 0, ic.created_at, ic.updated_at
    FROM new_scenario_developer_message nsdm
    CROSS JOIN scenario_developer_content sdc
    CROSS JOIN insert_scenario_developer_content_step1 ic
    WHERE NOT EXISTS (SELECT 1 FROM existing_scenario_developer_message)
),
scenario_developer_message AS (
    SELECT developer_message_id FROM existing_scenario_developer_message
    UNION ALL
    SELECT developer_message_id FROM new_scenario_developer_message
),
link_developer AS (
    INSERT INTO message_runs (message_id, run_id, created_at, updated_at)
    SELECT sdm.developer_message_id, ur.run_id, NOW(), NOW()
    FROM scenario_developer_message sdm
    CROSS JOIN upserted_run ur
    ON CONFLICT (message_id, run_id) DO UPDATE SET updated_at = NOW()
    RETURNING message_id as developer_message_id
),
link_system_to_developer AS (
    INSERT INTO message_tree (parent_id, child_id, active, created_at, updated_at)
    SELECT DISTINCT
        ls.system_message_id as parent_id,
        ld.developer_message_id as child_id,
        true as active,
        NOW() as created_at,
        NOW() as updated_at
    FROM link_system ls
    JOIN link_developer ld ON true
    WHERE NOT EXISTS (
        SELECT 1 FROM message_tree mt 
        WHERE mt.parent_id = ls.system_message_id 
        AND mt.child_id = ld.developer_message_id 
        AND mt.active = true
    )
)
SELECT 
    (SELECT message_id FROM upserted_message LIMIT 1)::text as message_id,
    (SELECT run_id FROM upserted_run LIMIT 1)::text as run_id,
    (SELECT audio FROM params LIMIT 1) as audio,
    (SELECT chat_id FROM params LIMIT 1)::text as chat_id,
    (SELECT group_id FROM target_group LIMIT 1)::text as group_id
$$;


--
-- Name: socket_member_tool_complete_finalize_v4(uuid, uuid, text, text, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_member_tool_complete_finalize_v4(chat_id uuid, run_id uuid, tool_call_id text, call_id text, message_id uuid, final_content text) RETURNS TABLE(message_id text, final_content text, completed boolean)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        chat_id, run_id, tool_call_id, call_id, message_id, final_content
),
-- Get tool call if tool_call_id or call_id provided
get_tool_call AS (
    SELECT tc.id as tool_call_id
    FROM params p
    JOIN calls tc ON (
        (p.tool_call_id IS NOT NULL AND tc.id::text = p.tool_call_id)
        OR (p.call_id IS NOT NULL AND tc.external_call_id = p.call_id)
    )
    LIMIT 1
),
-- Finalize tool call
finalize_tool_call AS (
    UPDATE calls
    SET completed = true,
        updated_at = NOW()
    FROM get_tool_call gtc
    WHERE calls.id = gtc.tool_call_id
    RETURNING id as tool_call_id
),
-- Get message from tool_call or use provided message_id
get_message_from_tool_call AS (
    SELECT DISTINCT ON (m.id) m.id as message_id
    FROM get_tool_call gtc
    JOIN calls tc ON tc.id = gtc.tool_call_id
    JOIN message_calls mc ON mc.call_id = tc.id
    JOIN message m ON m.id = mc.message_id
    ORDER BY m.id, m.created_at DESC
    LIMIT 1
),
selected_message AS (
    SELECT message_id FROM get_message_from_tool_call
    WHERE EXISTS (SELECT 1 FROM get_tool_call)
    UNION ALL
    SELECT message_id FROM params
    WHERE message_id IS NOT NULL
),
-- Update message content with final content
update_message_content_final AS (
    UPDATE contents
    SET content = p.final_content,
        updated_at = NOW()
    FROM params p,
         message_contents mc
    WHERE mc.content_id = contents.id
      AND mc.message_id = (SELECT message_id FROM selected_message LIMIT 1)
      AND mc.idx = 0
),
-- Mark message as completed
complete_message AS (
    UPDATE message
    SET completed = true,
        updated_at = NOW()
    WHERE id = (SELECT message_id FROM selected_message LIMIT 1)
    RETURNING id as message_id, completed
)
SELECT 
    (SELECT message_id FROM selected_message LIMIT 1)::text as message_id,
    (SELECT final_content FROM params LIMIT 1) as final_content,
    (SELECT completed FROM complete_message LIMIT 1) as completed
$$;


--
-- Name: socket_member_tool_progress_update_v4(uuid, uuid, text, text, text, text, text, text, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_member_tool_progress_update_v4(chat_id uuid, run_id uuid, tool_call_id text, call_id text, tool_name text, token text, accumulated_content text, arguments_raw text, message_id uuid DEFAULT NULL::uuid, parent_message_id uuid DEFAULT NULL::uuid) RETURNS TABLE(message_id text, tool_call_id text, accumulated_content text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        chat_id, run_id, tool_call_id, call_id, tool_name, 
        token, accumulated_content, arguments_raw, message_id, parent_message_id
),
-- Get tool_id from tool_name
get_tool_id AS (
    SELECT t.id as tool_id
    FROM tool t
    INNER JOIN resource_tools rt ON rt.tool_id = t.id
    WHERE t.name = (SELECT tool_name FROM params LIMIT 1)
      AND t.active = true
    LIMIT 1
),
-- Determine message role - member agent only handles speak (assistant role)
message_role AS (
    SELECT 'assistant'::message_role as role
),
-- Get or create tool_call
existing_tool_call AS (
    SELECT tc.id as tool_call_id, tc.external_call_id
    FROM params p
    JOIN calls tc ON (
        (p.tool_call_id IS NOT NULL AND tc.id::text = p.tool_call_id)
        OR (p.call_id IS NOT NULL AND tc.external_call_id = p.call_id)
    )
    LIMIT 1
),
create_tool_call AS (
    INSERT INTO calls (external_call_id, tool_id, template_id, arguments_raw, completed, created_at, updated_at)
    SELECT 
        COALESCE(p.call_id, 'member_' || p.tool_call_id),
        gt.tool_id,
        (SELECT template_id FROM tool_templates WHERE tool_id = gt.tool_id LIMIT 1),
        COALESCE(p.arguments_raw, ''),
        false,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN get_tool_id gt
    WHERE NOT EXISTS (SELECT 1 FROM existing_tool_call)
    RETURNING id as tool_call_id, external_call_id
),
selected_tool_call AS (
    SELECT tool_call_id::text, external_call_id FROM existing_tool_call
    UNION ALL
    SELECT tool_call_id::text, external_call_id FROM create_tool_call
),
-- Link call to message via message_calls (run_id removed from calls table)
link_call_to_message AS (
    INSERT INTO message_calls (message_id, call_id, created_at, updated_at)
    SELECT 
        m.id as message_id,
        uuid(stc.tool_call_id) as call_id,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN selected_tool_call stc
    JOIN message_runs mr ON mr.run_id = p.run_id
    JOIN message m ON m.id = mr.message_id
    WHERE m.role = 'assistant'
    ORDER BY m.created_at
    LIMIT 1
    ON CONFLICT (message_id, call_id) DO NOTHING
),
-- Update arguments_raw on calls if provided
update_call_arguments AS (
    UPDATE calls
    SET arguments_raw = COALESCE((SELECT p.arguments_raw FROM params p LIMIT 1), ''), updated_at = NOW()
    WHERE id IN (SELECT uuid(tool_call_id) FROM selected_tool_call)
      AND (SELECT p.arguments_raw FROM params p LIMIT 1) IS NOT NULL 
      AND (SELECT p.arguments_raw FROM params p LIMIT 1) != ''
    RETURNING calls.id
),
-- Get or create message
existing_message AS (
    SELECT p.message_id::uuid as message_id
    FROM params p
    WHERE p.message_id IS NOT NULL
    UNION ALL
    SELECT m.id as message_id
    FROM params p
    JOIN selected_tool_call stc ON true
    JOIN calls tc ON tc.id = uuid(stc.tool_call_id)
    JOIN message_calls mc ON mc.call_id = tc.id
    JOIN message m ON m.id = mc.message_id
    WHERE p.message_id IS NULL
    LIMIT 1
),
create_message AS (
    INSERT INTO message (role, completed, audio, created_at, updated_at)
    SELECT 
        mr.role,
        false,
        false,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN message_role mr
    WHERE NOT EXISTS (SELECT 1 FROM existing_message)
    RETURNING id as message_id
),
selected_message AS (
    SELECT message_id FROM existing_message
    UNION ALL
    SELECT message_id FROM create_message
),
-- Get existing content_id if message_contents exists, otherwise create new content
get_existing_content AS (
    SELECT cnt.id as content_id
    FROM params p
    CROSS JOIN selected_message sm
    JOIN message_contents mc ON mc.message_id = uuid(sm.message_id) AND mc.idx = 0
    JOIN contents cnt ON cnt.id = mc.content_id
    LIMIT 1
),
create_content AS (
    INSERT INTO contents (content, created_at, updated_at)
    SELECT 
        p.accumulated_content,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN selected_message sm
    CROSS JOIN selected_tool_call stc
    WHERE NOT EXISTS (SELECT 1 FROM get_existing_content)
    RETURNING id as content_id
),
selected_content_id AS (
    SELECT content_id FROM get_existing_content
    UNION ALL
    SELECT content_id FROM create_content
),
-- Update existing content or create new junction
update_existing_content AS (
    UPDATE contents cnt
    SET content = p.accumulated_content,
        updated_at = NOW()
    FROM params p
    CROSS JOIN selected_content_id sci
    WHERE cnt.id = sci.content_id
      AND EXISTS (SELECT 1 FROM get_existing_content)
),
upsert_message_content AS (
    INSERT INTO message_contents (message_id, content_id, idx, created_at, updated_at)
    SELECT 
        uuid(sm.message_id),
        sci.content_id,
        0,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN selected_message sm
    CROSS JOIN selected_content_id sci
    ON CONFLICT (message_id, content_id) DO UPDATE SET
        updated_at = NOW()
),
-- Link message to run
link_message_to_run AS (
    INSERT INTO message_runs (message_id, run_id, created_at, updated_at)
    SELECT 
        uuid(sm.message_id),
        p.run_id,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN selected_message sm
    ON CONFLICT (message_id, run_id) DO UPDATE SET updated_at = NOW()
),
-- Create branch if parent_message_id provided
create_branch AS (
    INSERT INTO message_tree (parent_id, child_id, active, created_at, updated_at)
    SELECT 
        p.parent_message_id,
        uuid(sm.message_id),
        true,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN selected_message sm
    WHERE p.parent_message_id IS NOT NULL
      AND NOT EXISTS (
          SELECT 1 FROM message_tree mt 
          WHERE mt.parent_id = p.parent_message_id 
          AND mt.child_id = uuid(sm.message_id)
          AND mt.active = true
      )
)
SELECT 
    (SELECT message_id FROM selected_message LIMIT 1)::text as message_id,
    (SELECT tool_call_id FROM selected_tool_call LIMIT 1)::text as tool_call_id,
    (SELECT accumulated_content FROM params LIMIT 1) as accumulated_content
$$;


--
-- Name: socket_prompt_tool_complete_finalize_v4(uuid, uuid, text, text, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_prompt_tool_complete_finalize_v4(chat_id uuid, run_id uuid, tool_call_id text, call_id text, message_id uuid, final_content text) RETURNS TABLE(message_id text, final_content text, completed boolean)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        chat_id, run_id, tool_call_id, call_id, message_id, final_content
),
-- Get tool call if tool_call_id or call_id provided
get_tool_call AS (
    SELECT tc.id as tool_call_id
    FROM params p
    JOIN calls tc ON (
        (p.tool_call_id IS NOT NULL AND tc.id::text = p.tool_call_id)
        OR (p.call_id IS NOT NULL AND tc.external_call_id = p.call_id)
    )
    LIMIT 1
),
-- Finalize tool call
finalize_tool_call AS (
    UPDATE calls
    SET completed = true,
        updated_at = NOW()
    FROM get_tool_call gtc
    WHERE calls.id = gtc.tool_call_id
    RETURNING id as tool_call_id
),
-- Get message from tool_call or use provided message_id
get_message_from_tool_call AS (
    SELECT DISTINCT ON (m.id) m.id as message_id
    FROM get_tool_call gtc
    JOIN calls tc ON tc.id = gtc.tool_call_id
    JOIN message_calls mc ON mc.call_id = tc.id
    JOIN message m ON m.id = mc.message_id
    ORDER BY m.id, m.created_at DESC
    LIMIT 1
),
selected_message AS (
    SELECT message_id FROM get_message_from_tool_call
    WHERE EXISTS (SELECT 1 FROM get_tool_call)
    UNION ALL
    SELECT message_id FROM params
    WHERE message_id IS NOT NULL
),
-- Update message content with final content
update_message_content_final AS (
