CREATE FUNCTION public.socket_rubric_generation_error_v4(profile_id uuid, error_message text, rubric_id uuid DEFAULT NULL::uuid, group_id uuid DEFAULT NULL::uuid) RETURNS TABLE(success boolean, message text, trace_id text)
    LANGUAGE sql
    AS $$
-- No-op: Just returns error info (no database operations)
-- trace_id comes from groups table, not parameter
SELECT 
    false as success,
    error_message as message,
    (SELECT trace_id FROM groups WHERE id = group_id LIMIT 1) as trace_id
$$;


--
-- Name: socket_rubric_generation_progress_v4(uuid, text, uuid, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
