CREATE FUNCTION public.socket_rubric_generation_progress_v4(profile_id uuid, progress_type text, rubric_id uuid DEFAULT NULL::uuid, group_id uuid DEFAULT NULL::uuid, message text DEFAULT NULL::text, tool_name text DEFAULT NULL::text) RETURNS TABLE(type text, message text, tool_name text, trace_id text)
