--
-- Name: socket_simulation_tool_complete_finalize_v4(uuid, uuid, uuid, text, uuid, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_simulation_tool_complete_finalize_v4(chat_id uuid, run_id uuid, tool_call_id uuid, call_id text, message_id uuid, final_content text, persona_id uuid DEFAULT NULL::uuid) RETURNS TABLE(message_id text, final_content text, completed boolean)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        chat_id, run_id, tool_call_id, call_id, message_id, final_content, persona_id
),
-- Get tool call if tool_call_id or call_id provided
get_tool_call AS (
    SELECT tc.id as tool_call_id
    FROM params p
    JOIN calls tc ON (
        (p.tool_call_id IS NOT NULL AND tc.id = p.tool_call_id)
        OR (p.call_id IS NOT NULL AND tc.external_call_id = p.call_id)
    )
    LIMIT 1
),
-- Finalize tool call
finalize_tool_call AS (
    UPDATE calls
    SET completed = true,
        updated_at = NOW()
    FROM get_tool_call gtc
    WHERE calls.id = gtc.tool_call_id
    RETURNING id as tool_call_id
),
-- Get message from tool_call or use provided message_id
get_message_from_tool_call AS (
    SELECT DISTINCT ON (m.id) m.id as message_id
    FROM get_tool_call gtc
    JOIN calls tc ON tc.id = gtc.tool_call_id
    JOIN message_calls mc ON mc.call_id = tc.id
    JOIN message m ON m.id = mc.message_id
    WHERE m.role = 'assistant'::message_role
    ORDER BY m.id, m.created_at DESC
    LIMIT 1
),
selected_message AS (
    SELECT message_id FROM get_message_from_tool_call
    WHERE EXISTS (SELECT 1 FROM get_tool_call)
    UNION ALL
    SELECT message_id FROM params
    WHERE message_id IS NOT NULL
),
-- Update message content with final content
update_message_content_final AS (
    UPDATE contents
    SET content = p.final_content,
        updated_at = NOW()
    FROM params p,
         message_contents mc
    WHERE mc.content_id = contents.id
      AND mc.message_id = (SELECT message_id FROM selected_message LIMIT 1)
      AND mc.idx = 0
),
-- Mark message as completed
complete_message AS (
    UPDATE message
    SET completed = true,
        updated_at = NOW()
    WHERE id = (SELECT message_id FROM selected_message LIMIT 1)
    RETURNING id as message_id, completed
),
-- Link message to persona if provided
link_message_to_persona AS (
    INSERT INTO message_personas (message_id, persona_id, created_at, updated_at)
    SELECT 
        (SELECT message_id FROM selected_message LIMIT 1),
        p.persona_id,
        NOW(),
        NOW()
    FROM params p
    WHERE p.persona_id IS NOT NULL
      AND NOT EXISTS (
          SELECT 1 FROM message_personas mp 
          WHERE mp.message_id = (SELECT message_id FROM selected_message LIMIT 1)
          AND mp.persona_id = p.persona_id
      )
)
SELECT 
    (SELECT message_id FROM selected_message LIMIT 1)::text as message_id,
    (SELECT final_content FROM params LIMIT 1) as final_content,
    (SELECT completed FROM complete_message LIMIT 1) as completed
$$;


--
-- Name: socket_simulation_tool_progress_update_v4(uuid, uuid, text, text, text, text, text, text, uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_simulation_tool_progress_update_v4(chat_id uuid, run_id uuid, tool_call_id text, call_id text, tool_name text, token text, accumulated_content text, arguments_raw text, message_id uuid DEFAULT NULL::uuid, parent_message_id uuid DEFAULT NULL::uuid, persona_id uuid DEFAULT NULL::uuid) RETURNS TABLE(message_id text, tool_call_id text, accumulated_content text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        chat_id, run_id, tool_call_id, call_id, tool_name, 
        token, accumulated_content, arguments_raw, message_id, parent_message_id, persona_id
),
-- Get tool_id from tool_name
get_tool_id AS (
    SELECT t.id as tool_id
    FROM tool t
    WHERE t.name = (SELECT tool_name FROM params LIMIT 1)
      AND t.active = true
    LIMIT 1
),
-- Determine message role - simulation agent handles speak (assistant role)
message_role AS (
    SELECT 'assistant'::message_role as role
),
-- Get or create tool_call
existing_tool_call AS (
    SELECT tc.id as tool_call_id, tc.external_call_id
    FROM params p
    JOIN calls tc ON (
        (p.tool_call_id IS NOT NULL AND tc.id::text = p.tool_call_id)
        OR (p.call_id IS NOT NULL AND tc.external_call_id = p.call_id)
    )
    LIMIT 1
),
create_tool_call AS (
    INSERT INTO calls (external_call_id, tool_id, template_id, arguments_raw, completed, created_at, updated_at)
    SELECT 
        COALESCE(p.call_id, 'simulation_' || p.tool_call_id),
        gt.tool_id,
        (SELECT template_id FROM tool_templates WHERE tool_id = gt.tool_id LIMIT 1),
        COALESCE(p.arguments_raw, ''),
        false,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN get_tool_id gt
    WHERE NOT EXISTS (SELECT 1 FROM existing_tool_call)
    RETURNING id as tool_call_id, external_call_id
),
selected_tool_call AS (
    SELECT tool_call_id::text, external_call_id FROM existing_tool_call
    UNION ALL
    SELECT tool_call_id::text, external_call_id FROM create_tool_call
),
-- Link call to message via message_calls (run_id removed from calls table)
link_call_to_message AS (
    INSERT INTO message_calls (message_id, call_id, created_at, updated_at)
    SELECT 
        m.id as message_id,
        uuid(stc.tool_call_id) as call_id,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN selected_tool_call stc
    JOIN message_runs mr ON mr.run_id = p.run_id
    JOIN message m ON m.id = mr.message_id
    WHERE m.role = 'assistant'
    ORDER BY m.created_at
    LIMIT 1
    ON CONFLICT (message_id, call_id) DO NOTHING
),
-- Update arguments_raw on calls if provided
update_call_arguments AS (
    UPDATE calls
    SET arguments_raw = COALESCE((SELECT p.arguments_raw FROM params p LIMIT 1), ''), updated_at = NOW()
    WHERE id IN (SELECT uuid(tool_call_id) FROM selected_tool_call)
      AND (SELECT p.arguments_raw FROM params p LIMIT 1) IS NOT NULL 
      AND (SELECT p.arguments_raw FROM params p LIMIT 1) != ''
    RETURNING calls.id
),
-- Get or create message
existing_message AS (
    SELECT p.message_id::uuid as message_id
    FROM params p
    WHERE p.message_id IS NOT NULL
    UNION ALL
    SELECT m.id as message_id
    FROM params p
    JOIN selected_tool_call stc ON true
    JOIN calls tc ON tc.id = uuid(stc.tool_call_id)
    JOIN message_calls mc ON mc.call_id = tc.id
    JOIN message m ON m.id = mc.message_id
    WHERE p.message_id IS NULL
    LIMIT 1
),
create_message AS (
    INSERT INTO message (role, completed, audio, created_at, updated_at)
    SELECT 
        mr.role,
        false,
        false,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN message_role mr
    WHERE NOT EXISTS (SELECT 1 FROM existing_message)
    RETURNING id as message_id
),
selected_message AS (
    SELECT message_id FROM existing_message
    UNION ALL
    SELECT message_id FROM create_message
),
-- Get existing content_id if message_contents exists, otherwise create new content
get_existing_content AS (
    SELECT cnt.id as content_id
    FROM params p
    CROSS JOIN selected_message sm
    JOIN message_contents mc ON mc.message_id = uuid(sm.message_id) AND mc.idx = 0
    JOIN contents cnt ON cnt.id = mc.content_id
    LIMIT 1
),
create_content AS (
    INSERT INTO contents (content, created_at, updated_at)
    SELECT 
        p.accumulated_content,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN selected_message sm
    CROSS JOIN selected_tool_call stc
    WHERE NOT EXISTS (SELECT 1 FROM get_existing_content)
    RETURNING id as content_id
),
selected_content_id AS (
    SELECT content_id FROM get_existing_content
    UNION ALL
    SELECT content_id FROM create_content
),
-- Update existing content or create new junction
update_existing_content AS (
    UPDATE contents cnt
    SET content = p.accumulated_content,
        updated_at = NOW()
    FROM params p
    CROSS JOIN selected_content_id sci
    WHERE cnt.id = sci.content_id
      AND EXISTS (SELECT 1 FROM get_existing_content)
),
upsert_message_content AS (
    INSERT INTO message_contents (message_id, content_id, idx, created_at, updated_at)
    SELECT 
        uuid(sm.message_id),
        sci.content_id,
        0,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN selected_message sm
    CROSS JOIN selected_content_id sci
    ON CONFLICT (message_id, content_id) DO UPDATE SET
        updated_at = NOW()
),
-- Link message to run
link_message_to_run AS (
    INSERT INTO message_runs (message_id, run_id, created_at, updated_at)
    SELECT 
        uuid(sm.message_id),
        p.run_id,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN selected_message sm
    ON CONFLICT (message_id, run_id) DO UPDATE SET updated_at = NOW()
),
-- Link message to persona if provided
link_message_to_persona AS (
    INSERT INTO message_personas (message_id, persona_id, created_at, updated_at)
    SELECT 
        uuid(sm.message_id),
        p.persona_id,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN selected_message sm
    WHERE p.persona_id IS NOT NULL
      AND NOT EXISTS (
          SELECT 1 FROM message_personas mp 
          WHERE mp.message_id = uuid(sm.message_id)
          AND mp.persona_id = p.persona_id
      )
),
-- Create branch if parent_message_id provided
create_branch AS (
    INSERT INTO message_tree (parent_id, child_id, active, created_at, updated_at)
    SELECT 
        p.parent_message_id,
        uuid(sm.message_id),
        true,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN selected_message sm
    WHERE p.parent_message_id IS NOT NULL
      AND NOT EXISTS (
          SELECT 1 FROM message_tree mt 
          WHERE mt.parent_id = p.parent_message_id 
          AND mt.child_id = uuid(sm.message_id)
          AND mt.active = true
      )
)
SELECT 
    (SELECT message_id FROM selected_message LIMIT 1)::text as message_id,
    (SELECT tool_call_id FROM selected_tool_call LIMIT 1)::text as tool_call_id,
    (SELECT accumulated_content FROM params LIMIT 1) as accumulated_content
$$;


--
-- Name: socket_standard_group_descriptions_complete_v4(boolean, uuid, integer, text, types.q_standard_group_descriptions_complete_v4_description[], uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_standard_group_descriptions_complete_v4(success boolean, rubric_id uuid, updated_count integer, message text, descriptions types.q_standard_group_descriptions_complete_v4_description[], profile_id uuid, group_id uuid DEFAULT NULL::uuid) RETURNS TABLE(success boolean, rubric_id uuid, updated_count integer, trace_id text, message text, descriptions types.q_standard_group_descriptions_complete_v4_description[])
    LANGUAGE sql
    AS $$
-- No-op: Just returns success (no database operations)
-- trace_id comes from groups table, not parameter
SELECT 
    success,
    rubric_id,
    updated_count,
    (SELECT trace_id FROM groups WHERE id = group_id LIMIT 1) as trace_id,
    COALESCE(message, 'Standard group descriptions completed successfully') as message,
    COALESCE(descriptions, ARRAY[]::types.q_standard_group_descriptions_complete_v4_description[]) as descriptions
$$;


--
-- Name: socket_standard_group_descriptions_error_v4(boolean, text, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_standard_group_descriptions_error_v4(success boolean, message text, profile_id uuid, group_id uuid DEFAULT NULL::uuid) RETURNS TABLE(success boolean, message text, trace_id text)
    LANGUAGE sql
    AS $$
-- No-op: Just returns error info (no database operations)
-- trace_id comes from groups table, not parameter
SELECT 
    success,
    message,
    (SELECT trace_id FROM groups WHERE id = group_id LIMIT 1) as trace_id
$$;


--
-- Name: socket_standard_group_descriptions_progress_v4(uuid, text, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_standard_group_descriptions_progress_v4(profile_id uuid, type text, group_id uuid DEFAULT NULL::uuid, message text DEFAULT NULL::text, tool_name text DEFAULT NULL::text) RETURNS TABLE(type text, message text, tool_name text, trace_id text)
    LANGUAGE sql
    AS $$
-- No-op: Just returns progress info (no database operations)
-- trace_id comes from groups table, not parameter
SELECT 
    type,
    COALESCE(message, 'Progress updated') as message,
    tool_name as tool_name,
    (SELECT trace_id FROM groups WHERE id = group_id LIMIT 1) as trace_id
$$;


--
-- Name: socket_start_simulation_attempt_v4(uuid, boolean, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_start_simulation_attempt_v4(simulation_id uuid, infinite_mode boolean, profile_id uuid DEFAULT NULL::uuid, scenario_id_override uuid DEFAULT NULL::uuid) RETURNS TABLE(attempt_id text, chat_id text, chat_title text, scenario_id text, scenario_name text, problem_statement text, needs_generation boolean, content_type text, video_id text, trace_id text, simulation_data types.q_start_simulation_attempt_v4_simulation_data, scenario_metadata types.q_start_simulation_attempt_v4_scenario_metadata)
    LANGUAGE sql
    AS $$
WITH params AS (
    -- Wrap all function parameters in a CTE for asyncpg prepared statement compatibility
    SELECT 
        simulation_id::uuid as simulation_id,
        infinite_mode::boolean as infinite_mode,
        profile_id::uuid as profile_id,
        scenario_id_override::uuid as scenario_id_override
),
-- Create the attempt first
new_attempt AS (
    INSERT INTO simulation_attempts (simulation_id, infinite_mode, created_at)
    SELECT p.simulation_id, p.infinite_mode, now()
    FROM params p
    RETURNING id as attempt_id
),
-- Create attempt_profiles junction if profile exists
attempt_profile_link AS (
    INSERT INTO attempt_profiles (attempt_id, profile_id, active, created_at, updated_at)
    SELECT na.attempt_id, p.profile_id, true, now(), now()
    FROM new_attempt na
    CROSS JOIN params p
    WHERE p.profile_id IS NOT NULL
    RETURNING attempt_id
),
-- Get simulation data
simulation_data AS (
    SELECT 
        s.id,
        (SELECT n.name FROM simulation_names sn JOIN names n ON sn.name_id = n.id WHERE sn.simulation_id = s.id LIMIT 1) as title,
        (SELECT (SELECT d2.description FROM department_descriptions dd JOIN descriptions d2 ON dd.description_id = d2.id WHERE dd.department_id = d.id LIMIT 1) FROM scenario_descriptions sd JOIN descriptions d ON sd.description_id = d.id WHERE sd.scenario_id = s.id LIMIT 1) as description,
        EXISTS (SELECT 1 FROM scenario_flags sf JOIN flags fl ON sf.flag_id = fl.id WHERE sf.scenario_id = s.id AND fl.name = 'active' AND sf.type = 'active'::type_scenario_flags AND sf.value = TRUE) as active,
        EXISTS (SELECT 1 FROM simulation_flags sf JOIN flags fl ON sf.flag_id = fl.id WHERE sf.simulation_id = s.id AND fl.name = 'practice' AND sf.type = 'practice'::type_simulation_flags AND sf.value = TRUE) as practice_simulation,
        (SELECT sd.agent_domain_id FROM simulation_agent_domains sd WHERE sd.simulation_id = s.id AND sd.type = 'text'::type_simulation_domains LIMIT 1) as simulation_text_domain_id,
        (SELECT sd.agent_domain_id FROM simulation_agent_domains sd WHERE sd.simulation_id = s.id AND sd.type = 'voice'::type_simulation_domains LIMIT 1) as simulation_voice_domain_id,
        (SELECT rga.rubric_id FROM simulation_scenarios ss 
         JOIN simulation_scenarios_scenario_rubric_grade_agents sssrga ON sssrga.simulation_id = ss.simulation_id AND sssrga.scenario_id = ss.scenario_id
         JOIN scenario_rubric_grade_agents srga ON srga.id = sssrga.scenario_rubric_grade_agent_id
         JOIN rubric_grade_agents rga ON rga.id = srga.grade_agent_id
         WHERE ss.simulation_id = s.id 
           AND EXISTS (SELECT 1 FROM simulation_scenario_flags ssf 
             WHERE ssf.simulation_id = ss.simulation_id 
               AND ssf.scenario_id = ss.scenario_id 
               AND ssf.type = 'active'::type_simulation_scenario_flags 
               AND ssf.value = true)
         ORDER BY (SELECT sp.value FROM scenario_positions sp WHERE sp.simulation_id = ss.simulation_id AND sp.scenario_id = ss.scenario_id LIMIT 1)
         LIMIT 1) as rubric_id
    FROM params p
    JOIN simulation s ON s.id = p.simulation_id
),
-- Get simulation scenarios in order
simulation_scenarios AS (
    SELECT 
        ss.scenario_id,
        (SELECT sp.value FROM scenario_positions sp WHERE sp.simulation_id = ss.simulation_id AND sp.scenario_id = ss.scenario_id LIMIT 1) as position
    FROM params p
    JOIN simulation_scenarios ss ON ss.simulation_id = p.simulation_id 
      AND EXISTS (SELECT 1 FROM simulation_scenario_flags ssf 
        WHERE ssf.simulation_id = ss.simulation_id 
          AND ssf.scenario_id = ss.scenario_id 
          AND ssf.type = 'active'::type_simulation_scenario_flags 
          AND ssf.value = true)
    ORDER BY (SELECT sp.value FROM scenario_positions sp WHERE sp.simulation_id = ss.simulation_id AND sp.scenario_id = ss.scenario_id LIMIT 1)
),
-- Determine content type (always scenario now - videos are accessed through scenarios)
content_type_check AS (
    SELECT 
        'scenario' as content_type,
        NULL::uuid as first_video_id
),
-- Determine chosen scenario
chosen_scenario_id AS (
    SELECT 
        CASE 
            WHEN p.scenario_id_override IS NOT NULL THEN p.scenario_id_override
            WHEN EXISTS(SELECT 1 FROM simulation_scenarios) THEN 
                (SELECT scenario_id FROM simulation_scenarios 
                 ORDER BY position LIMIT 1)
            ELSE (
                SELECT s.id 
                FROM scenario s 
                ORDER BY random() 
                LIMIT 1
            )
        END as scenario_id
    FROM params p
),
-- Resolve department_id for agent prompt selection (scenario -> profile -> any active)
scenario_dept AS (
    SELECT 
        csi.scenario_id,
        (SELECT sd.department_id FROM scenario_departments sd 
         WHERE sd.scenario_id = csi.scenario_id AND sd.active = true LIMIT 1) as department_id
    FROM chosen_scenario_id csi
),
profile_dept AS (
    -- Get first department from profile's accessible departments
    SELECT d.id as department_id
    FROM params p
    JOIN departments d ON EXISTS (SELECT 1 FROM department_flags df JOIN flags fl ON df.flag_id = fl.id WHERE df.department_id = d.id AND fl.name = 'active' AND df.type = 'active'::type_department_flags AND df.value = true)
    JOIN profile_departments pd ON pd.department_id = d.id
    WHERE pd.profile_id = p.profile_id 
      AND pd.active = true
    LIMIT 1
),
any_active_dept AS (
    -- Get any active department as last resort
    SELECT d.id as department_id
    FROM department d
    WHERE EXISTS (SELECT 1 FROM department_flags df JOIN flags fl ON df.flag_id = fl.id WHERE df.department_id = d.id AND fl.name = 'active' AND df.type = 'active'::type_department_flags AND df.value = true)
    LIMIT 1
),
resolved_dept AS (
    -- Resolve department_id with fallback: scenario -> profile -> any active
    SELECT COALESCE(
        (SELECT department_id FROM scenario_dept),
        (SELECT department_id FROM profile_dept),
        (SELECT department_id FROM any_active_dept)
    ) as department_id
),
-- Get active settings for profile (for key lookup via setting_provider_keys)
default_settings AS (
    -- Get settings with no department links (cross-department/default)
    SELECT s.id as settings_id
    FROM setting s
    WHERE EXISTS (SELECT 1 FROM setting_flags sf JOIN flags fl ON sf.flag_id = fl.id WHERE sf.setting_id = s.id AND fl.name = 'active' AND sf.type = 'active'::type_setting_flags AND sf.value = TRUE)
      AND NOT EXISTS (
          SELECT 1 FROM department_settings sd 
          WHERE sd.settings_id = s.id AND sd.active = true
      )
    LIMIT 1
),
profile_primary_department AS (
    -- Get profile's primary department ID (only if profile_id is provided)
    SELECT pd.department_id
    FROM params p
    JOIN profile_departments pd ON pd.profile_id = p.profile_id
    WHERE pd.is_primary = TRUE 
      AND pd.active = true
    LIMIT 1
),
dept_specific_settings AS (
    -- Get department-specific settings (if primary_department_id exists)
    SELECT s.id as settings_id
    FROM setting s
    JOIN department_settings sd ON sd.settings_id = s.id
    JOIN profile_primary_department ppd ON sd.department_id = ppd.department_id
    WHERE EXISTS (SELECT 1 FROM setting_flags sf JOIN flags fl ON sf.flag_id = fl.id WHERE sf.setting_id = s.id AND fl.name = 'active' AND sf.type = 'active'::type_setting_flags AND sf.value = TRUE) 
      AND sd.active = true
    LIMIT 1
),
active_settings AS (
    -- For authenticated users: prefer department-specific, then default, then any active
    -- For NULL profile_id: use default settings
    SELECT 
        COALESCE(
            (SELECT settings_id FROM dept_specific_settings),
            (SELECT settings_id FROM default_settings),
            (SELECT id FROM setting s WHERE EXISTS (SELECT 1 FROM setting_flags sf JOIN flags fl ON sf.flag_id = fl.id WHERE sf.setting_id = s.id AND fl.name = 'active' AND sf.type = 'active'::type_setting_flags AND sf.value = TRUE) LIMIT 1)
        ) as settings_id
),
-- Document data for composite type aggregation
document_data AS (
    SELECT 
        s.id as scenario_id,
        d.id as document_id,
        (SELECT n.name FROM document_names dn JOIN names n ON dn.name_id = n.id WHERE dn.document_id = d.id LIMIT 1),
        u.file_path,
        u.mime_type
    FROM scenario s
    CROSS JOIN chosen_scenario_id csi
    LEFT JOIN scenario_documents sd ON sd.scenario_id = s.id AND sd.active = true
    LEFT JOIN documents d ON d.id = sd.document_id
    LEFT JOIN document_uploads du ON du.document_id = d.id AND du.active = true
    LEFT JOIN uploads u ON u.id = du.upload_id
    WHERE s.id = csi.scenario_id
),
-- Parameter item data for composite type aggregation
parameter_item_data AS (
    SELECT 
        s.id as scenario_id,
        f.id as field_id,
        (SELECT n.name FROM field_names fn JOIN names n ON fn.name_id = n.id WHERE fn.field_id = f.id LIMIT 1),
        (SELECT d.description FROM field_descriptions fd JOIN descriptions d ON fd.description_id = d.id WHERE fd.field_id = f.id LIMIT 1),
        (SELECT pf.parameter_id FROM parameter_fields pf WHERE pf.field_id = f.id LIMIT 1),
        (SELECT n.name FROM parameter_names pn JOIN names n ON pn.name_id = n.id WHERE pn.parameter_id = p_param.id LIMIT 1) as parameter_name
    FROM scenario s
    CROSS JOIN chosen_scenario_id csi
    LEFT JOIN scenario_fields sf ON sf.scenario_id = s.id AND sf.active = true
    LEFT JOIN fields f ON f.id = sf.field_id
    LEFT JOIN parameters p_param ON p_param.id = (SELECT pf.parameter_id FROM parameter_fields pf WHERE pf.field_id = f.id LIMIT 1)
    WHERE s.id = csi.scenario_id
),
-- Get full scenario data with all metadata
-- CRITICAL FIX: Use DISTINCT ON to ensure only ONE row per scenario
-- Multiple agents/models for the same persona can cause multiple rows, leading to duplicate chats
scenario_full_data_raw AS (
    SELECT 
        s.id as scenario_id,
        (SELECT n.name FROM scenario_names sn JOIN names n ON sn.name_id = n.id WHERE sn.scenario_id = s.id LIMIT 1) as scenario_name,
        ps.problem_statement,
        EXISTS (SELECT 1 FROM scenario_flags sf JOIN flags fl ON sf.flag_id = fl.id WHERE sf.scenario_id = s.id AND fl.name = 'active' AND sf.type = 'active'::type_scenario_flags AND sf.value = TRUE) as active,
        false as generated,
        false as default_scenario,
        -- Persona data
        sp.persona_id::text as persona_id,
        (SELECT n.name FROM persona_names pn JOIN names n ON pn.name_id = n.id WHERE pn.persona_id = sp.persona_id LIMIT 1) as persona_name,
        COALESCE(
            COALESCE(pr_prompt_dept.system_prompt, pr_prompt_default.system_prompt),
            ''
        ) as system_prompt,
        COALESCE(tl.temperature, 0.0) as temperature,
        rl.reasoning_level as reasoning,
        (SELECT c.hex_code FROM persona_colors pc JOIN colors c ON pc.color_id = c.id WHERE pc.persona_id = sp.persona_id LIMIT 1) as persona_color,
        (SELECT i.name FROM persona_icons pi JOIN icons i ON pi.icon_id = i.id WHERE pi.persona_id = sp.persona_id LIMIT 1) as persona_icon,
        -- Model data
        m.id as model_id,
        m.value as model_name,
        COALESCE(n_prov.name, '') as provider,
        COALESCE(e.base_url, '') as base_url,
        k.key as api_key,
        -- Check if scenario needs generation
        CASE 
            WHEN ps.problem_statement IS NULL OR ps.problem_statement = '' THEN true
            ELSE false
        END as needs_generation
    FROM scenario s
    LEFT JOIN scenario_problem_statements sps ON sps.scenario_id = s.id AND sps.active = true
    LEFT JOIN problem_statements ps ON ps.id = sps.problem_statement_id
    CROSS JOIN chosen_scenario_id csi
    LEFT JOIN scenario_personas sp ON sp.scenario_id = s.id AND sp.active = true
    CROSS JOIN simulation_data sd_agents
    LEFT JOIN agent_domains adom_text ON adom_text.domain_id = sd_agents.simulation_text_domain_id
    LEFT JOIN agents a ON a.id = adom_text.agent_id AND EXISTS (SELECT 1 FROM agent_flags af JOIN flags fl ON af.flag_id = fl.id WHERE af.agent_id = a.id AND fl.name = 'active' AND af.type = 'active'::type_agent_flags AND af.value = true)
    LEFT JOIN agent_models am ON am.agent_id = a.id
    LEFT JOIN models m ON m.id = am.model_id
    -- Join temperature and reasoning from model levels via agent
    LEFT JOIN agent_temperature_levels atl ON atl.agent_id = a.id AND atl.active = true
    LEFT JOIN model_temperature_levels mtl ON mtl.temperature_level_id = atl.temperature_level_id AND mtl.model_id = m.id 
LEFT JOIN temperature_levels tl ON tl.id = mtl.temperature_level_id AND tl.active = true
    LEFT JOIN agent_reasoning_levels arl ON arl.agent_id = a.id AND arl.active = true
    -- IMPORTANT: Only join reasoning levels that belong to the agent's model (m.id = mrl.model_id)
    LEFT JOIN model_reasoning_levels mrl ON mrl.reasoning_level_id = arl.reasoning_level_id AND mrl.model_id = m.id 
LEFT JOIN reasoning_levels rl ON rl.id = mrl.reasoning_level_id AND rl.active = true
    -- Try department-specific agent prompt first, fall back to default prompt
    CROSS JOIN resolved_dept rd
    LEFT JOIN agent_department_prompts adp_prompt ON adp_prompt.agent_id = a.id 
        AND adp_prompt.department_id = rd.department_id
        AND adp_prompt.active = true
    LEFT JOIN prompts pr_prompt_dept ON pr_prompt_dept.id = adp_prompt.prompt_id
    LEFT JOIN agent_prompts ap_default ON ap_default.agent_id = a.id AND ap_default.active = true
    LEFT JOIN prompts pr_prompt_default ON pr_prompt_default.id = ap_default.prompt_id
    LEFT JOIN model_endpoints me_j ON me_j.model_id = m.id
    LEFT JOIN endpoints e ON e.id = me_j.endpoint_id AND e.active = true
    -- Get keys via settings system: provider -> active settings -> setting_provider_keys
    LEFT JOIN model_providers mp ON mp.model_id = m.id
    LEFT JOIN providers p_prov ON p_prov.id = mp.providers_id
    LEFT JOIN provider pr_prov ON pr_prov.id = p_prov.provider_id
    LEFT JOIN provider_names pn_prov ON pn_prov.provider_id = pr_prov.id
    LEFT JOIN names n_prov ON n_prov.id = pn_prov.name_id
    CROSS JOIN active_settings act_s
    LEFT JOIN setting_provider_keys spk ON spk.providers_id = p_prov.id 
        AND spk.settings_id = act_s.settings_id 
        AND spk.active = true
    LEFT JOIN keys k ON k.id = spk.key_id AND EXISTS (SELECT 1 FROM key_flags kf JOIN flags fl ON kf.flag_id = fl.id WHERE kf.key_id = k.id AND fl.name = 'active' AND kf.type = 'active'::type_key_flags AND kf.value = TRUE) = true
    WHERE s.id = csi.scenario_id
    GROUP BY s.id, (SELECT n.name FROM scenario_names sn JOIN names n ON sn.name_id = n.id WHERE sn.scenario_id = s.id LIMIT 1), ps.problem_statement, EXISTS (SELECT 1 FROM scenario_flags sf JOIN flags fl ON sf.flag_id = fl.id WHERE sf.scenario_id = s.id AND fl.name = 'active' AND sf.type = 'active'::type_scenario_flags AND sf.value = TRUE), 
             CASE WHEN ps.problem_statement IS NULL OR ps.problem_statement = '' THEN true ELSE false END, sp.persona_id, (SELECT n.name FROM persona_names pn JOIN names n ON pn.name_id = n.id WHERE pn.persona_id = sp.persona_id LIMIT 1), pr_prompt_dept.system_prompt, pr_prompt_default.system_prompt, 
             COALESCE(tl.temperature, 0.0), rl.reasoning_level, (SELECT c.hex_code FROM persona_colors pc JOIN colors c ON pc.color_id = c.id WHERE pc.persona_id = sp.persona_id LIMIT 1), (SELECT i.name FROM persona_icons pi JOIN icons i ON pi.icon_id = i.id WHERE pi.persona_id = sp.persona_id LIMIT 1), m.id, m.value, n_prov.name,
             k.key, e.base_url, act_s.settings_id
),
-- Select only ONE row per scenario (deterministic: pick first model by ID)
scenario_full_data AS (
    SELECT DISTINCT ON (scenario_id) *
    FROM scenario_full_data_raw
    ORDER BY scenario_id, model_id
),
-- Create simulation chat (only for scenarios, not videos)
new_chat AS (
    INSERT INTO chat (
        created_at, title, scenario_id, completed, updated_at
    )
    SELECT 
        now(),
        COALESCE(sfd.scenario_name, 'New Simulation'),
        sfd.scenario_id,
        false,
        now()
    FROM new_attempt na
    CROSS JOIN scenario_full_data sfd
    CROSS JOIN content_type_check ctc
    WHERE ctc.content_type = 'scenario'
    RETURNING id as chat_id, title as chat_title, created_at, updated_at
),
-- Create group (trace_id auto-generated by database default)
new_group AS (
    INSERT INTO groups (created_at, updated_at)
    SELECT nc.created_at, nc.updated_at
    FROM new_chat nc
    RETURNING id as group_id, trace_id
),
-- Link chat to group
chat_group_link AS (
    INSERT INTO chat_groups (chat_id, group_id, created_at, updated_at)
    SELECT nc.chat_id, ng.group_id, nc.created_at, nc.updated_at
    FROM new_chat nc
    CROSS JOIN new_group ng
    RETURNING chat_id, group_id
),
-- Create attempt_chats junction table entry (only if chat was created)
attempt_chat_link AS (
    INSERT INTO attempt_chats (attempt_id, chat_id, created_at, updated_at)
    SELECT na.attempt_id, nc.chat_id, nc.created_at, nc.updated_at
    FROM new_attempt na
    CROSS JOIN new_chat nc
    RETURNING attempt_id, chat_id
)
-- Return all data in single row
SELECT 
    na.attempt_id::text,
    CASE WHEN ctc.content_type = 'scenario' THEN nc.chat_id::text ELSE NULL::text END as chat_id,
    CASE WHEN ctc.content_type = 'scenario' THEN nc.chat_title ELSE NULL::text END as chat_title,
    CASE WHEN ctc.content_type = 'scenario' THEN sfd.scenario_id::text ELSE NULL::text END as scenario_id,
    CASE WHEN ctc.content_type = 'scenario' THEN sfd.scenario_name ELSE NULL::text END as scenario_name,
    CASE WHEN ctc.content_type = 'scenario' THEN sfd.problem_statement ELSE NULL::text END as problem_statement,
    CASE WHEN ctc.content_type = 'scenario' THEN sfd.needs_generation ELSE false END as needs_generation,
    ctc.content_type,
    NULL::text as video_id,
    ng.trace_id::text as trace_id,
    -- Simulation metadata as composite type
    (sd.id::text, sd.title, sd.description, sd.active, sd.practice_simulation, sd.rubric_id::text)::types.q_start_simulation_attempt_v4_simulation_data as simulation_data,
    -- Scenario metadata as composite type (only for scenarios)
    CASE 
        WHEN ctc.content_type = 'scenario' THEN
            (
                sfd.persona_id::text,
                sfd.persona_name,
                sfd.system_prompt,
                sfd.temperature,
                sfd.reasoning,
                sfd.persona_color,
                sfd.persona_icon,
                sfd.model_id::text,
                sfd.model_name,
                sfd.provider,
                sfd.base_url,
                sfd.api_key,
                COALESCE(
                    (SELECT ARRAY_AGG(
                        (dd.document_id::text, dd.name, dd.file_path, dd.mime_type)::types.q_start_simulation_attempt_v4_document
                        ORDER BY dd.document_id
                    ) FROM document_data dd WHERE dd.scenario_id = sfd.scenario_id),
                    '{}'::types.q_start_simulation_attempt_v4_document[]
                ),
                COALESCE(
                    (SELECT ARRAY_AGG(
                        (pid.field_id::text, pid.name, pid.description, pid.parameter_id::text, pid.parameter_name)::types.q_start_simulation_attempt_v4_parameter_item
                        ORDER BY pid.field_id
                    ) FROM parameter_item_data pid WHERE pid.scenario_id = sfd.scenario_id),
                    '{}'::types.q_start_simulation_attempt_v4_parameter_item[]
                ),
                sfd.active,
                sfd.default_scenario,
                sfd.generated
            )::types.q_start_simulation_attempt_v4_scenario_metadata
        ELSE NULL::types.q_start_simulation_attempt_v4_scenario_metadata
    END as scenario_metadata
FROM new_attempt na
CROSS JOIN content_type_check ctc
CROSS JOIN simulation_data sd
LEFT JOIN new_chat nc ON ctc.content_type = 'scenario'
LEFT JOIN attempt_chat_link acl ON acl.chat_id = nc.chat_id AND acl.attempt_id = na.attempt_id AND ctc.content_type = 'scenario'
LEFT JOIN chat_group_link cgl ON cgl.chat_id = nc.chat_id AND ctc.content_type = 'scenario'
LEFT JOIN new_group ng ON ng.group_id = cgl.group_id AND ctc.content_type = 'scenario'
LEFT JOIN scenario_full_data sfd ON ctc.content_type = 'scenario' AND sfd.scenario_id = (SELECT scenario_id FROM chosen_scenario_id)
$$;


--
-- Name: socket_text_generation_complete_v4(uuid, uuid, uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_text_generation_complete_v4(profile_id uuid, run_id uuid, resource_id uuid DEFAULT NULL::uuid, group_id uuid DEFAULT NULL::uuid, department_id uuid DEFAULT NULL::uuid) RETURNS TABLE(success boolean, message text, tool_results jsonb, trace_id text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    tool_results_val jsonb;
    trace_id_val text;
BEGIN
    -- Get trace_id from groups table if group_id provided
    IF group_id IS NOT NULL THEN
        SELECT trace_id INTO trace_id_val FROM groups WHERE id = group_id LIMIT 1;
    END IF;

    -- Get tool results
    SELECT tool_results INTO tool_results_val
    FROM socket_get_text_tool_call_results_v4(run_id);

    -- Return completion data
    RETURN QUERY
    SELECT 
        true as success,
        'Text generation completed successfully' as message,
        COALESCE(tool_results_val, '{}'::jsonb) as tool_results,
        trace_id_val as trace_id;
END;
$$;


--
-- Name: socket_text_tool_progress_update_v4(uuid, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_text_tool_progress_update_v4(run_id uuid, tool_call_id text, progress_type text, call_id text DEFAULT NULL::text, tool_name text DEFAULT NULL::text, arguments_delta text DEFAULT ''::text) RETURNS TABLE(tool_id uuid, tool_type text, tool_call_id text, persisted_call_id text, tool_name text, arguments_raw text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT run_id, tool_call_id, call_id, tool_name, arguments_delta, progress_type
),
-- Get tool_id AND tool_type from tool_name + agent_tools junction table
-- Works with any agent (not hardcoded to document)
get_tool_info AS (
    SELECT t.id as tool_id, COALESCE(rt.resource::text, '') as tool_type, t.name as tool_name
    FROM params p
    JOIN tool t ON t.name = p.tool_name
    JOIN agent_tools at ON at.tool_id = t.id
    JOIN run r_run ON r_run.id = p.run_id
    LEFT JOIN resource_tools rt ON rt.tool_id = t.id
    WHERE at.agent_id = r_run.agent_id
      AND at.active = true
      AND t.active = true
    LIMIT 1
),
-- Get or create tool_call (by call_id or tool_call_id)
existing_tool_call AS (
    SELECT tc.id as tool_call_id, tc.external_call_id
    FROM params p
    JOIN calls tc ON (
        (p.tool_call_id IS NOT NULL AND tc.id::text = p.tool_call_id)
        OR (p.call_id IS NOT NULL AND tc.external_call_id = p.call_id)
    )
    LIMIT 1
),
create_tool_call AS (
    INSERT INTO calls (external_call_id, tool_id, template_id, arguments_raw, completed, created_at, updated_at)
    SELECT 
        COALESCE(p.call_id, 'text_' || p.tool_call_id),
        gt.tool_id,
        (SELECT template_id FROM tool_templates WHERE tool_id = gt.tool_id LIMIT 1),
        '',
        false,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN get_tool_info gt
    WHERE NOT EXISTS (SELECT 1 FROM existing_tool_call)
    RETURNING id as tool_call_id, external_call_id
),
selected_tool_call AS (
    SELECT tool_call_id::text, external_call_id FROM existing_tool_call
    UNION ALL
    SELECT tool_call_id::text, external_call_id FROM create_tool_call
),
-- Link call to message via message_calls (run_id removed from calls table)
link_call_to_message AS (
    INSERT INTO message_calls (message_id, call_id, created_at, updated_at)
    SELECT 
        m.id as message_id,
        uuid(stc.tool_call_id) as call_id,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN selected_tool_call stc
    JOIN message_runs mr ON mr.run_id = p.run_id
    JOIN message m ON m.id = mr.message_id
    WHERE m.role = 'assistant'
    ORDER BY m.created_at
    LIMIT 1
    ON CONFLICT (message_id, call_id) DO NOTHING
),
-- Accumulate arguments_raw (SQL accumulates!)
accumulate_arguments AS (
    SELECT 
        uuid(stc.tool_call_id) as tool_call_id,
        CASE 
            WHEN p.progress_type = 'tool_call_start' THEN COALESCE(p.arguments_delta, '')
            WHEN p.progress_type = 'tool_call_progress' THEN 
                COALESCE(
                    (SELECT arguments_raw FROM calls c 
                     WHERE c.id = uuid(stc.tool_call_id)),
                    ''
                ) || COALESCE(p.arguments_delta, '')
            ELSE COALESCE(p.arguments_delta, '')
        END as accumulated_raw
    FROM params p
    CROSS JOIN selected_tool_call stc
),
-- Update arguments_raw on calls (arguments_raw is now a direct column)
update_call_arguments AS (
    UPDATE calls
    SET arguments_raw = (SELECT accumulated_raw FROM accumulate_arguments LIMIT 1), updated_at = NOW()
    WHERE id IN (SELECT tool_call_id FROM accumulate_arguments)
      AND (SELECT accumulated_raw FROM accumulate_arguments LIMIT 1) IS NOT NULL 
      AND (SELECT accumulated_raw FROM accumulate_arguments LIMIT 1) != ''
    RETURNING calls.id
)
SELECT 
    (SELECT tool_id FROM get_tool_info LIMIT 1) as tool_id,
    (SELECT tool_type FROM get_tool_info LIMIT 1) as tool_type,
    (SELECT tool_call_id FROM selected_tool_call LIMIT 1) as tool_call_id,
    (SELECT external_call_id FROM selected_tool_call LIMIT 1) as persisted_call_id,
    (SELECT tool_name FROM get_tool_info LIMIT 1) as tool_name,
    (SELECT accumulated_raw FROM accumulate_arguments LIMIT 1) as arguments_raw
$$;


--
-- Name: socket_update_document_name_v4(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_update_document_name_v4(document_id uuid, name text) RETURNS TABLE(document_id uuid, name text)
    LANGUAGE sql
    AS $_$
WITH params AS (
    SELECT $1 as document_id, $2 as name
),
-- Insert/update name in names table
name_resource AS (
    INSERT INTO names (name, created_at, updated_at)
    SELECT name, NOW(), NOW()
    FROM params
    WHERE name IS NOT NULL AND name != ''
    ON CONFLICT (name) DO UPDATE SET updated_at = NOW()
    RETURNING id as name_id
),
-- Update document (without name column)
document_update AS (
    UPDATE document
    SET updated_at = NOW()
    WHERE id = (SELECT document_id FROM params)
    RETURNING id as document_id
),
-- Remove old name links
remove_old_name AS (
    DELETE FROM document_names
    WHERE document_id = (SELECT document_id FROM params)
      AND name_id NOT IN (SELECT name_id FROM name_resource)
),
-- Link document to new name
link_document_name AS (
    INSERT INTO document_names (document_id, name_id, created_at, updated_at)
    SELECT 
        du.document_id,
        nr.name_id,
        NOW(),
        NOW()
    FROM document_update du
    CROSS JOIN name_resource nr
    ON CONFLICT (document_id, name_id) DO UPDATE SET updated_at = NOW()
)
SELECT 
    du.document_id,
    (SELECT n.name FROM names n JOIN name_resource nr ON n.id = nr.name_id LIMIT 1) as name
FROM document_update du
$_$;


--
-- Name: socket_update_grade_final_v4(uuid, text, boolean, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_update_grade_final_v4(grade_id_param uuid, description_param text, passed_param boolean, score_param integer) RETURNS TABLE(id text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_conversation_id uuid;
BEGIN
    -- Update grade
    UPDATE grade 
    SET description = description_param,
        passed = passed_param,
        score = score_param
    WHERE id = grade_id_param;
    
    -- Update conversation description if linked
    SELECT conversation_id INTO v_conversation_id
    FROM grade_conversations
    WHERE grade_id = grade_id_param
    LIMIT 1;
    
    IF v_conversation_id IS NOT NULL THEN
        UPDATE conversations
        SET description = description_param,
            updated_at = NOW()
        WHERE id = v_conversation_id;
    END IF;
    
    RETURN QUERY SELECT grade_id_param::text;
END $$;


--
-- Name: socket_update_profile_to_active_v4(uuid, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_update_profile_to_active_v4(profile_id uuid, last_active timestamp with time zone) RETURNS TABLE(profile_exists boolean, profile_id uuid)
    LANGUAGE sql
    AS $$
WITH get_active_flag AS (
    -- Get the active flag ID
    SELECT id as flag_id
    FROM flags
    WHERE name = 'active'
    LIMIT 1
),
insert_or_update_flag AS (
    -- Insert or update profile_flags to set active = true
    INSERT INTO profile_flags (profile_id, flag_id, type, value)
    SELECT 
        profile_id,
        (SELECT flag_id FROM get_active_flag),
        'active'::type_profile_flags,
        true
    FROM get_active_flag
    ON CONFLICT (profile_id, flag_id, type) 
    DO UPDATE SET value = true
    RETURNING profile_id::uuid as profile_id
),
update_profile AS (
    -- Return profile_id if flag was set
    SELECT profile_id FROM insert_or_update_flag
),
insert_activity AS (
    -- Insert activity record
    INSERT INTO profile_activity (profile_id, last_active)
    SELECT 
        up.profile_id,
        last_active
    FROM update_profile up
)
SELECT 
    EXISTS(SELECT 1 FROM update_profile)::boolean as profile_exists,
    (SELECT profile_id FROM update_profile LIMIT 1)::uuid as profile_id
$$;


--
-- Name: socket_update_profile_to_inactive_v4(uuid, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_update_profile_to_inactive_v4(profile_id uuid, last_active timestamp with time zone) RETURNS TABLE(profile_exists boolean, profile_id uuid)
    LANGUAGE sql
    AS $$
WITH get_active_flag AS (
    -- Get the active flag ID
    SELECT id as flag_id
    FROM flags_resource
    WHERE name = 'active'
    LIMIT 1
),
insert_or_update_flag AS (
    -- Insert or update profile_flags_junction to set active = false
    INSERT INTO profile_flags_junction (profile_id, flag_id, value) SELECT profile_id,
        (SELECT flag_id FROM get_active_flag),
        false
    FROM get_active_flag
    ON CONFLICT (profile_id, flag_id) 
    DO UPDATE SET value = false
    RETURNING profile_id::uuid as profile_id
),
update_profile AS (
    -- Return profile_id if flag was set
    SELECT profile_id FROM insert_or_update_flag
),
insert_activity AS (
    -- Insert view_activity_entry record
    INSERT INTO activity_entry (last_active)
    SELECT last_active
    FROM update_profile up
    RETURNING id as activity_id
),
link_activity_to_profile AS (
    -- Link activity to profile via junction table
    INSERT INTO profiles_activity_connection (profiles_id, activity_id)
    SELECT up.profile_id, ia.activity_id
    FROM update_profile up
    CROSS JOIN insert_activity ia
)
SELECT 
    EXISTS(SELECT 1 FROM update_profile)::boolean as profile_exists,
    (SELECT profile_id FROM update_profile LIMIT 1)::uuid as profile_id
$$;


--
-- Name: socket_update_rubric_name_v4(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_update_rubric_name_v4(profile_id uuid, rubric_id uuid, name text) RETURNS TABLE(rubric_id uuid, name text)
    LANGUAGE sql
    AS $$
WITH get_or_create_name AS (
    -- Get or create name in names table
    INSERT INTO names (name, created_at, updated_at)
    SELECT socket_update_rubric_name_v4.name, NOW(), NOW()
    WHERE socket_update_rubric_name_v4.name IS NOT NULL AND socket_update_rubric_name_v4.name != ''
    ON CONFLICT (name) DO UPDATE SET updated_at = NOW()
    RETURNING id as name_id, name as name_value
),
update_rubric_name AS (
    -- Update rubric name (delete old, insert new)
    DELETE FROM rubric_names
    WHERE rubric_id = socket_update_rubric_name_v4.rubric_id
    RETURNING rubric_id
),
link_rubric_name AS (
    -- Link new name to rubric
    INSERT INTO rubric_names (rubric_id, name_id, created_at, updated_at)
    SELECT socket_update_rubric_name_v4.rubric_id, gocn.name_id, NOW(), NOW()
    FROM get_or_create_name gocn
    WHERE gocn.name_id IS NOT NULL
),
update_rubric AS (
    UPDATE rubric
    SET updated_at = NOW()
    WHERE id = socket_update_rubric_name_v4.rubric_id
    RETURNING id as rubric_id
)
SELECT ur.rubric_id, COALESCE(gocn.name_value, (SELECT n.name FROM rubric_names rn JOIN names n ON rn.name_id = n.id WHERE rn.rubric_id = ur.rubric_id LIMIT 1)) as name
FROM update_rubric ur
LEFT JOIN get_or_create_name gocn ON true
$$;


--
-- Name: socket_update_standard_descriptions_v4(uuid, types.i_update_standard_descriptions_v4_description[], uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_update_standard_descriptions_v4(rubric_id uuid, descriptions types.i_update_standard_descriptions_v4_description[], profile_id uuid, group_id uuid DEFAULT NULL::uuid) RETURNS TABLE(updated_count integer, group_id uuid, trace_id text, descriptions types.q_update_standard_descriptions_v4_description[])
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT rubric_id AS rubric_id, descriptions AS descriptions, profile_id AS profile_id, group_id AS group_id
),
create_group_if_needed AS (
    -- Create new group if group_id is NULL
    INSERT INTO groups (created_at, updated_at)
    SELECT NOW(), NOW()
    FROM params p
    WHERE p.group_id IS NULL
    RETURNING id as group_id, trace_id
),
group_data AS (
    -- Use existing group if provided, otherwise use newly created group
    SELECT 
        COALESCE(
            (SELECT g.id FROM groups g CROSS JOIN params p WHERE g.id = p.group_id),
            (SELECT cg.group_id FROM create_group_if_needed cg)
        ) as group_id,
        COALESCE(
            (SELECT g.trace_id FROM groups g CROSS JOIN params p WHERE g.id = p.group_id),
            (SELECT cg.trace_id FROM create_group_if_needed cg)
        ) as trace_id
),
descriptions_data AS (
    -- Unnest descriptions array (composite type array)
    SELECT 
        (unnest(descriptions)).standard_group_id,
        (unnest(descriptions)).standard_id,
        (unnest(descriptions)).description
    FROM (SELECT descriptions FROM params) as d
),
updated_standards AS (
    UPDATE standards s
    SET description = dd.description
    FROM descriptions_data dd
    WHERE s.id = dd.standard_id
      AND s.standard_group_id = dd.standard_group_id
      AND EXISTS (
          SELECT 1 FROM rubric_standard_groups rsg
          WHERE rsg.standard_group_id = s.standard_group_id
          AND rsg.rubric_id = (SELECT rubric_id FROM params)
          AND rsg.active = true
      )
    RETURNING s.standard_group_id, s.id as standard_id, (SELECT (SELECT d.description FROM document_descriptions dd JOIN descriptions d ON dd.description_id = d.id WHERE dd.document_id = d.id LIMIT 1) FROM scenario_descriptions sd JOIN descriptions d ON sd.description_id = d.id WHERE sd.scenario_id = s.id LIMIT 1)
)
SELECT 
    COUNT(*)::int as updated_count,
    (SELECT group_id FROM group_data LIMIT 1) as group_id,
    (SELECT trace_id FROM group_data LIMIT 1) as trace_id,
    -- Return descriptions as array of composite types (not JSONB)
    COALESCE(
        ARRAY_AGG(
            (us.standard_group_id, us.standard_id, us.description)::types.q_update_standard_descriptions_v4_description
            ORDER BY us.standard_group_id, us.standard_id
        ),
        ARRAY[]::types.q_update_standard_descriptions_v4_description[]
    ) as descriptions
FROM updated_standards us
$$;


