--
-- Name: test_create_simulation_scenario_link_v4(uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_create_simulation_scenario_link_v4(input_simulation_id uuid, input_scenario_id uuid, input_position integer DEFAULT 1) RETURNS TABLE(simulation_id uuid, scenario_id uuid, active boolean, "position" integer, created_at timestamp with time zone)
    LANGUAGE sql
    AS $$
    WITH inserted_link AS (
        INSERT INTO simulation_scenarios(simulation_id, scenario_id)
        VALUES (
            test_create_simulation_scenario_link_v4.input_simulation_id,
            test_create_simulation_scenario_link_v4.input_scenario_id
        )
        RETURNING simulation_id, scenario_id, created_at
    ),
    inserted_flag AS (
        INSERT INTO simulation_scenario_flags(simulation_id, scenario_id, scenario_flag_id, type, value, created_at, updated_at, generated, mcp)
        SELECT 
            il.simulation_id,
            il.scenario_id,
            sf.id,
            'active'::type_simulation_scenario_flags,
            true,
            NOW(),
            NOW(),
            false,
            false
        FROM inserted_link il
        CROSS JOIN flags sf
        WHERE sf.name = 'active'
        LIMIT 1
    ),
    inserted_position AS (
        INSERT INTO scenario_positions(simulation_id, scenario_id, value, created_at, updated_at, generated, mcp)
        SELECT 
            il.simulation_id,
            il.scenario_id,
            COALESCE(test_create_simulation_scenario_link_v4.input_position, 1),
            NOW(),
            NOW(),
            false,
            false
        FROM inserted_link il
    )
    SELECT 
        il.simulation_id,
        il.scenario_id,
        true as active,
        COALESCE(test_create_simulation_scenario_link_v4.input_position, 1) as "position",
        il.created_at
    FROM inserted_link il;
$$;


--
-- Name: test_create_test_agent_v4(uuid, text, text, text, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_create_test_agent_v4(model_id uuid, name text DEFAULT 'Test Agent'::text, description text DEFAULT 'Test Description'::text, role text DEFAULT 'assistant'::text, active boolean DEFAULT true) RETURNS TABLE(agent_id uuid, name text, description text, model_id uuid, active boolean, role text, created_at timestamp with time zone)
    LANGUAGE sql
    AS $$
    WITH new_agent AS (
        INSERT INTO agents DEFAULT VALUES
        RETURNING id, created_at
    ),
    name_resource AS (
        INSERT INTO names(name)
        VALUES (COALESCE(test_create_test_agent_v4.name, 'Test Agent'))
        RETURNING id
    ),
    description_resource AS (
        INSERT INTO descriptions(description)
        VALUES (COALESCE(test_create_test_agent_v4.description, 'Test Description'))
        RETURNING id
    ),
    active_flag AS (
        SELECT id FROM flags WHERE name = 'active' LIMIT 1
    ),
    agent_name_link AS (
        INSERT INTO agent_names(agent_id, name_id)
        SELECT na.id, nr.id
        FROM new_agent na, name_resource nr
        RETURNING agent_id, name_id
    ),
    agent_description_link AS (
        INSERT INTO agent_descriptions(agent_id, description_id)
        SELECT na.id, dr.id
        FROM new_agent na, description_resource dr
        RETURNING agent_id, description_id
    ),
    agent_flag_link AS (
        INSERT INTO agent_flags(agent_id, flag_id, type, value)
        SELECT na.id, af.id, 'active'::type_agent_flags, COALESCE(test_create_test_agent_v4.active, true)
        FROM new_agent na, active_flag af
        RETURNING agent_id
    ),
    agent_model_link AS (
        INSERT INTO agent_models(agent_id, model_id)
        SELECT na.id, test_create_test_agent_v4.model_id
        FROM new_agent na
        WHERE test_create_test_agent_v4.model_id IS NOT NULL
        RETURNING agent_id
    )
    SELECT 
        na.id as agent_id,
        (SELECT n.name FROM agent_names an JOIN names n ON an.name_id = n.id WHERE an.agent_id = na.id LIMIT 1) as name,
        (SELECT d.description FROM agent_descriptions ad JOIN descriptions d ON ad.description_id = d.id WHERE ad.agent_id = na.id LIMIT 1) as description,
        (SELECT am.model_id FROM agent_models am WHERE am.agent_id = na.id LIMIT 1) as model_id,
        EXISTS (SELECT 1 FROM agent_flags af JOIN flags fl ON af.flag_id = fl.id WHERE af.agent_id = na.id AND fl.name = 'active' AND af.type = 'active'::type_agent_flags AND af.value = TRUE) as active,
        COALESCE(test_create_test_agent_v4.role, 'assistant') as role,
        na.created_at
    FROM new_agent na;
$$;


