--
-- Name: test_create_test_parameter_v4(text, text, boolean, boolean, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_create_test_parameter_v4(parameter_name text, parameter_description text DEFAULT 'Test parameter description'::text, parameter_active boolean DEFAULT true, parameter_document_parameter boolean DEFAULT false, parameter_simulation_parameter boolean DEFAULT false) RETURNS TABLE(parameter_id uuid, name text, description text, active boolean, document_parameter boolean, simulation_parameter boolean, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE sql
    AS $$
    WITH new_parameter AS (
        INSERT INTO parameters DEFAULT VALUES
        RETURNING id, created_at, updated_at
    ),
    name_resource AS (
        INSERT INTO names(name)
        VALUES (parameter_name)
        RETURNING id
    ),
    description_resource AS (
        INSERT INTO descriptions(description)
        VALUES (COALESCE(parameter_description, 'Test parameter description'))
        RETURNING id
    ),
    active_flag AS (
        SELECT id FROM flags WHERE name = 'active' LIMIT 1
    ),
    document_parameter_flag AS (
        SELECT id FROM flags WHERE name = 'document_parameter' LIMIT 1
    ),
    simulation_parameter_flag AS (
        SELECT id FROM flags WHERE name = 'simulation_parameter' LIMIT 1
    ),
    parameter_name_link AS (
        INSERT INTO parameter_names(parameter_id, name_id)
        SELECT np.id, nr.id
        FROM new_parameter np, name_resource nr
        RETURNING parameter_id
    ),
    parameter_description_link AS (
        INSERT INTO parameter_descriptions(parameter_id, description_id)
        SELECT np.id, dr.id
        FROM new_parameter np, description_resource dr
        RETURNING parameter_id
    ),
    parameter_active_flag_link AS (
        INSERT INTO parameter_flags(parameter_id, flag_id, type, value)
        SELECT np.id, af.id, 'active'::type_parameter_flags, COALESCE(parameter_active, true)
        FROM new_parameter np, active_flag af
        RETURNING parameter_id
    ),
    parameter_document_flag_link AS (
        INSERT INTO parameter_flags(parameter_id, flag_id, type, value)
        SELECT np.id, dpf.id, 'document_parameter'::type_parameter_flags, COALESCE(parameter_document_parameter, false)
        FROM new_parameter np, document_parameter_flag dpf
        WHERE COALESCE(parameter_document_parameter, false) = true
        RETURNING parameter_id
    ),
    parameter_simulation_flag_link AS (
        INSERT INTO parameter_flags(parameter_id, flag_id, type, value)
        SELECT np.id, spf.id, 'simulation_parameter'::type_parameter_flags, COALESCE(parameter_simulation_parameter, false)
        FROM new_parameter np, simulation_parameter_flag spf
        WHERE COALESCE(parameter_simulation_parameter, false) = true
        RETURNING parameter_id
    )
    SELECT 
        np.id AS parameter_id,
        (SELECT n.name FROM parameter_names pn JOIN names n ON pn.name_id = n.id WHERE pn.parameter_id = np.id LIMIT 1) AS name,
        (SELECT d.description FROM parameter_descriptions pd JOIN descriptions d ON pd.description_id = d.id WHERE pd.parameter_id = np.id LIMIT 1) AS description,
        EXISTS (SELECT 1 FROM parameter_flags pf JOIN flags fl ON pf.flag_id = fl.id WHERE pf.parameter_id = np.id AND fl.name = 'active' AND pf.type = 'active'::type_parameter_flags AND pf.value = TRUE) AS active,
        EXISTS (SELECT 1 FROM parameter_flags pf JOIN flags fl ON pf.flag_id = fl.id WHERE pf.parameter_id = np.id AND fl.name = 'document_parameter' AND pf.type = 'document_parameter'::type_parameter_flags AND pf.value = TRUE) AS document_parameter,
        EXISTS (SELECT 1 FROM parameter_flags pf JOIN flags fl ON pf.flag_id = fl.id WHERE pf.parameter_id = np.id AND fl.name = 'simulation_parameter' AND pf.type = 'simulation_parameter'::type_parameter_flags AND pf.value = TRUE) AS simulation_parameter,
        np.created_at,
        np.updated_at
    FROM new_parameter np;
$$;


--
-- Name: test_create_test_persona_v4(text, text, text, text, boolean, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_create_test_persona_v4(persona_name text DEFAULT 'Test Persona'::text, description text DEFAULT 'Test Description'::text, color text DEFAULT '#000000'::text, icon text DEFAULT 'user'::text, active boolean DEFAULT true, instructions text DEFAULT NULL::text) RETURNS TABLE(persona_id uuid, name text, description text, color text, icon text, active boolean, instructions text, created_at timestamp with time zone)
    LANGUAGE sql
    AS $$
    WITH new_persona AS (
        INSERT INTO personas(created_at, updated_at)
        VALUES (NOW(), NOW())
        RETURNING id, created_at
    ),
    new_instruction AS (
        INSERT INTO instructions(template, active, created_at, updated_at)
        SELECT 
            COALESCE(test_create_test_persona_v4.instructions, ''),
            true,
            NOW(),
            NOW()
        WHERE test_create_test_persona_v4.instructions IS NOT NULL
        RETURNING id
    ),
    persona_instruction_link AS (
        INSERT INTO persona_instructions(persona_id, instruction_id, created_at, updated_at)
        SELECT np.id, ni.id, NOW(), NOW()
        FROM new_persona np
        CROSS JOIN new_instruction ni
        WHERE ni.id IS NOT NULL
        RETURNING persona_id
    ),
    name_resource AS (
        INSERT INTO names(name)
        VALUES (COALESCE(test_create_test_persona_v4.persona_name, 'Test Persona'))
        RETURNING id
    ),
    description_resource AS (
        INSERT INTO descriptions(description)
        VALUES (COALESCE(test_create_test_persona_v4.description, 'Test Description'))
        RETURNING id
    ),
    color_resource AS (
        INSERT INTO colors(name, description, hex_code)
        VALUES ('Test Color', 'Test Color Description', COALESCE(test_create_test_persona_v4.color, '#000000'))
        RETURNING id
    ),
    icon_resource AS (
        INSERT INTO icons(name, description, value)
        VALUES ('Test Icon', 'Test Icon Description', COALESCE(test_create_test_persona_v4.icon, 'user'))
        RETURNING id
    ),
    active_flag AS (
        SELECT id FROM flags WHERE name = 'active' LIMIT 1
    ),
    persona_name_link AS (
        INSERT INTO persona_names(persona_id, name_id)
        SELECT np.id, nr.id
        FROM new_persona np, name_resource nr
        RETURNING persona_id
    ),
    persona_description_link AS (
        INSERT INTO persona_descriptions(persona_id, description_id)
        SELECT np.id, dr.id
        FROM new_persona np, description_resource dr
        RETURNING persona_id
    ),
    persona_color_link AS (
        INSERT INTO persona_colors(persona_id, color_id)
        SELECT np.id, cr.id
        FROM new_persona np, color_resource cr
        RETURNING persona_id
    ),
    persona_icon_link AS (
        INSERT INTO persona_icons(persona_id, icon_id)
        SELECT np.id, ir.id
        FROM new_persona np, icon_resource ir
        RETURNING persona_id
    ),
    persona_flag_link AS (
        INSERT INTO persona_flags(persona_id, flag_id, type, value)
        SELECT np.id, af.id, 'active'::type_persona_flags, COALESCE(test_create_test_persona_v4.active, true)
        FROM new_persona np, active_flag af
        RETURNING persona_id
    )
    SELECT 
        np.id as persona_id,
        (SELECT n.name FROM persona_names pn JOIN names n ON pn.name_id = n.id WHERE pn.persona_id = np.id LIMIT 1) as name,
        (SELECT d.description FROM persona_descriptions pd JOIN descriptions d ON pd.description_id = d.id WHERE pd.persona_id = np.id LIMIT 1) as description,
        (SELECT c.hex_code FROM persona_colors pc JOIN colors c ON pc.color_id = c.id WHERE pc.persona_id = np.id LIMIT 1) as color,
        (SELECT i.value FROM persona_icons pi JOIN icons i ON pi.icon_id = i.id WHERE pi.persona_id = np.id LIMIT 1) as icon,
        EXISTS (SELECT 1 FROM persona_flags pf JOIN flags fl ON pf.flag_id = fl.id WHERE pf.persona_id = np.id AND fl.name = 'active' AND pf.type = 'active'::type_persona_flags AND pf.value = TRUE) as active,
        (SELECT i.template FROM persona_instructions pi JOIN instructions i ON pi.instruction_id = i.id WHERE pi.persona_id = np.id LIMIT 1) as instructions,
        np.created_at
    FROM new_persona np;
$$;


