--
-- Name: test_create_test_rubric_v4(text, text, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_create_test_rubric_v4(name text DEFAULT 'Test Rubric'::text, description text DEFAULT 'Test Description'::text, points integer DEFAULT 100, pass_points integer DEFAULT 70) RETURNS TABLE(rubric_id uuid)
    LANGUAGE sql
    AS $$
    WITH new_rubric AS (
        INSERT INTO rubrics DEFAULT VALUES
        RETURNING id
    ),
    name_resource AS (
        INSERT INTO names(name)
        VALUES (test_create_test_rubric_v4.name)
        RETURNING id
    ),
    description_resource AS (
        INSERT INTO descriptions(description)
        VALUES (test_create_test_rubric_v4.description)
        RETURNING id
    ),
    points_resource AS (
        INSERT INTO points(value)
        VALUES (test_create_test_rubric_v4.points)
        ON CONFLICT (value) DO NOTHING
        RETURNING id
    ),
    points_lookup AS (
        SELECT id FROM points WHERE value = test_create_test_rubric_v4.points LIMIT 1
    ),
    pass_points_resource AS (
        INSERT INTO points(value)
        VALUES (test_create_test_rubric_v4.pass_points)
        ON CONFLICT (value) DO NOTHING
        RETURNING id
    ),
    pass_points_lookup AS (
        SELECT id FROM points WHERE value = test_create_test_rubric_v4.pass_points LIMIT 1
    ),
    active_flag AS (
        SELECT id FROM flags WHERE name = 'active' LIMIT 1
    ),
    rubric_name_link AS (
        INSERT INTO rubric_names(rubric_id, name_id)
        SELECT nr.id, nrr.id
        FROM new_rubric nr, name_resource nrr
        RETURNING rubric_id
    ),
    rubric_description_link AS (
        INSERT INTO rubric_descriptions(rubric_id, description_id)
        SELECT nr.id, dr.id
        FROM new_rubric nr, description_resource dr
        RETURNING rubric_id
    ),
    rubric_points_link AS (
        INSERT INTO rubric_points(rubric_id, point_id, type)
        SELECT nr.id, COALESCE(pr.id, pl.id), 'total'::type_rubric_points
        FROM new_rubric nr, points_resource pr FULL OUTER JOIN points_lookup pl ON true
        RETURNING rubric_id
    ),
    rubric_pass_points_link AS (
        INSERT INTO rubric_points(rubric_id, point_id, type)
        SELECT nr.id, COALESCE(ppr.id, ppl.id), 'pass'::type_rubric_points
        FROM new_rubric nr, pass_points_resource ppr FULL OUTER JOIN pass_points_lookup ppl ON true
        RETURNING rubric_id
    ),
    rubric_flag_link AS (
        INSERT INTO rubric_flags(rubric_id, flag_id, type, value)
        SELECT nr.id, af.id, 'active'::type_rubric_flags, true
        FROM new_rubric nr, active_flag af
        RETURNING rubric_id
    )
    SELECT nr.id as rubric_id
    FROM new_rubric nr;
$$;


--
-- Name: test_create_test_rubric_v4(text, text, integer, integer, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_create_test_rubric_v4(rubric_name text, rubric_description text, rubric_points integer, rubric_pass_points integer, rubric_active boolean) RETURNS TABLE(rubric_id uuid, name text, description text, points integer, pass_points integer, active boolean, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE sql
    AS $$
    WITH new_rubric AS (
        INSERT INTO rubrics(created_at, updated_at)
        VALUES (NOW(), NOW())
        RETURNING id, created_at, updated_at
    ),
    rubric_artifact_link AS (
        INSERT INTO rubric_artifacts(rubric_id, artifact, created_at, updated_at)
        SELECT nr.id, 'rubric'::artifacts, NOW(), NOW()
        FROM new_rubric nr
        RETURNING rubric_id
    ),
    name_resource AS (
        INSERT INTO names(name)
        VALUES (rubric_name)
        RETURNING id
    ),
    description_resource AS (
        INSERT INTO descriptions(description)
        VALUES (rubric_description)
        RETURNING id
    ),
    points_resource AS (
        INSERT INTO points(value)
        VALUES (rubric_points)
        RETURNING id
    ),
    pass_points_resource AS (
        INSERT INTO points(value)
        VALUES (rubric_pass_points)
        RETURNING id
    ),
    active_flag AS (
        SELECT id FROM flags WHERE name = 'active' LIMIT 1
    ),
    rubric_name_link AS (
        INSERT INTO rubric_names(rubric_id, name_id)
        SELECT nr.id, nrr.id
        FROM new_rubric nr, name_resource nrr
        RETURNING rubric_id
    ),
    rubric_description_link AS (
        INSERT INTO rubric_descriptions(rubric_id, description_id)
        SELECT nr.id, dr.id
        FROM new_rubric nr, description_resource dr
        RETURNING rubric_id
    ),
    rubric_points_link AS (
        INSERT INTO rubric_points(rubric_id, point_id, type)
        SELECT nr.id, pr.id, 'total'::type_rubric_points
        FROM new_rubric nr, points_resource pr
        RETURNING rubric_id
    ),
    rubric_pass_points_link AS (
        INSERT INTO rubric_points(rubric_id, point_id, type)
        SELECT nr.id, ppr.id, 'pass'::type_rubric_points
        FROM new_rubric nr, pass_points_resource ppr
        RETURNING rubric_id
    ),
    rubric_flag_link AS (
        INSERT INTO rubric_flags(rubric_id, flag_id, type, value)
        SELECT nr.id, af.id, 'active'::type_rubric_flags, rubric_active
        FROM new_rubric nr, active_flag af
        RETURNING rubric_id
    )
    SELECT 
        nr.id AS rubric_id,
        (SELECT n.name FROM rubric_names rn JOIN names n ON rn.name_id = n.id WHERE rn.rubric_id = nr.id LIMIT 1) AS name,
        (SELECT d.description FROM rubric_descriptions rd JOIN descriptions d ON rd.description_id = d.id WHERE rd.rubric_id = nr.id LIMIT 1) AS description,
        (SELECT p.value FROM rubric_points rp JOIN points p ON rp.point_id = p.id WHERE rp.rubric_id = nr.id AND rp.type = 'total'::type_rubric_points LIMIT 1) AS points,
        (SELECT p.value FROM rubric_points rp JOIN points p ON rp.point_id = p.id WHERE rp.rubric_id = nr.id AND rp.type = 'pass'::type_rubric_points LIMIT 1) AS pass_points,
        EXISTS (SELECT 1 FROM rubric_flags rf JOIN flags fl ON rf.flag_id = fl.id WHERE rf.rubric_id = nr.id AND fl.name = 'active' AND rf.type = 'active'::type_rubric_flags AND rf.value = TRUE) AS active,
        nr.created_at,
        nr.updated_at
    FROM new_rubric nr;
$$;


