CREATE FUNCTION public.test_create_test_run_v4(department_id uuid, model_id uuid, agent_id uuid DEFAULT NULL::uuid, entity_type text DEFAULT 'agent'::text, profile_id uuid DEFAULT NULL::uuid, entity_id uuid DEFAULT NULL::uuid) RETURNS TABLE(run_id uuid, department_id uuid, model_id uuid, agent_id uuid)
