$$;


--
-- Name: test_create_test_scenario_v4(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_create_test_scenario_v4(name text DEFAULT 'Test Scenario'::text) RETURNS TABLE(scenario_id uuid)
    LANGUAGE sql
    AS $$
    WITH new_scenario AS (
        INSERT INTO scenarios DEFAULT VALUES
        RETURNING id
    ),
    name_resource AS (
        INSERT INTO names(name)
        VALUES (test_create_test_scenario_v4.name)
        RETURNING id
    ),
    active_flag AS (
        SELECT id FROM flags WHERE name = 'active' LIMIT 1
    ),
    scenario_name_link AS (
        INSERT INTO scenario_names(scenario_id, name_id)
        SELECT ns.id, nr.id
        FROM new_scenario ns, name_resource nr
        RETURNING scenario_id
    ),
    scenario_flag_link AS (
        INSERT INTO scenario_flags(scenario_id, flag_id, type, value)
        SELECT ns.id, af.id, 'active'::type_scenario_flags, true
        FROM new_scenario ns, active_flag af
        RETURNING scenario_id
    )
    SELECT ns.id as scenario_id
    FROM new_scenario ns;
$$;


--
-- Name: test_create_test_scenario_v4(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_create_test_scenario_v4(scenario_name text DEFAULT 'Test Scenario'::text, scenario_problem_statement text DEFAULT 'Test problem statement'::text) RETURNS TABLE(scenario_id uuid, name text, problem_statement text, active boolean, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_scenario_id uuid;
BEGIN
    -- Insert scenario
    INSERT INTO scenarios(name, active)
    VALUES (
        COALESCE(test_create_test_scenario_v4.scenario_name, 'Test Scenario'),
        true
    )
    RETURNING id INTO v_scenario_id;

    -- Insert self-referencing tree edge
    INSERT INTO scenario_tree(parent_id, child_id, active)
    VALUES (v_scenario_id, v_scenario_id, true);

    -- Insert problem statement
    INSERT INTO scenario_problem_statements(scenario_id, problem_statement, active)
    VALUES (
        v_scenario_id,
        COALESCE(test_create_test_scenario_v4.scenario_problem_statement, 'Test problem statement'),
        true
    );

    -- Return result
    RETURN QUERY
    SELECT 
        s.id as scenario_id,
        s.name,
        sps.problem_statement,
        s.active,
        s.created_at
    FROM scenarios s
    JOIN scenario_problem_statements sps ON sps.scenario_id = s.id AND sps.active = true
    WHERE s.id = v_scenario_id;
END;
$$;


--
-- Name: test_create_test_scenario_with_parameter_item_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_create_test_scenario_with_parameter_item_v4(input_parameter_item_id uuid) RETURNS TABLE(scenario_id uuid, name text, active boolean, parameter_item_id uuid, link_active boolean, created_at timestamp with time zone)
    LANGUAGE sql
    AS $$
    WITH name_resource AS (
        INSERT INTO names(name)
        VALUES ('Test Scenario')
        RETURNING id
    ),
    active_flag AS (
        SELECT id FROM flags WHERE name = 'active' LIMIT 1
    ),
    new_scenario AS (
        INSERT INTO scenarios DEFAULT VALUES
        RETURNING id AS scenario_id, created_at
    ),
    scenario_name_link AS (
        INSERT INTO scenario_names(scenario_id, name_id)
        SELECT ns.scenario_id, nr.id
        FROM new_scenario ns, name_resource nr
        RETURNING scenario_id
    ),
    scenario_flag_link AS (
        INSERT INTO scenario_flags(scenario_id, flag_id, type, value)
        SELECT ns.scenario_id, af.id, 'active'::type_scenario_flags, true
        FROM new_scenario ns, active_flag af
        RETURNING scenario_id
    ),
    new_link AS (
        INSERT INTO scenario_parameters(scenario_id, parameter_id, active)
        SELECT scenario_id, input_parameter_item_id, true
        FROM new_scenario
        RETURNING scenario_id, parameter_id, active AS link_active
    )
    SELECT 
        ns.scenario_id,
        (SELECT n.name FROM scenario_names sn JOIN names n ON sn.name_id = n.id WHERE sn.scenario_id = ns.scenario_id LIMIT 1) as name,
        EXISTS (SELECT 1 FROM scenario_flags sf JOIN flags fl ON sf.flag_id = fl.id WHERE sf.scenario_id = ns.scenario_id AND fl.name = 'active' AND sf.type = 'active'::type_scenario_flags AND sf.value = TRUE) as active,
        nl.parameter_id AS parameter_item_id,
        nl.link_active,
        ns.created_at
    FROM new_scenario ns
    JOIN new_link nl ON ns.scenario_id = nl.scenario_id;
$$;


