--
-- Name: test_get_active_models_count_v4(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_active_models_count_v4() RETURNS TABLE(count bigint)
    LANGUAGE sql STABLE
    AS $$
    SELECT COUNT(*) as count
    FROM models m
    WHERE EXISTS (SELECT 1 FROM model_flags mf JOIN flags fl ON mf.flag_id = fl.id WHERE mf.model_id = m.id AND fl.name = 'active' AND mf.type = 'active'::type_model_flags AND mf.value = TRUE);
$$;


--
-- Name: test_get_activity_by_message_and_endpoint_v4(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_activity_by_message_and_endpoint_v4(p_message text, p_endpoint text) RETURNS TABLE(id uuid, message text, endpoint text, profile_id uuid, error boolean, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
    SELECT id, message, endpoint, profile_id, error, created_at
    FROM activity
    WHERE message = p_message AND endpoint = p_endpoint
    ORDER BY created_at DESC
    LIMIT 1;
$$;


