--
-- Name: test_get_agent_by_id_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_agent_by_id_v4(input_agent_id uuid) RETURNS TABLE(agent_id uuid, name text, description text, model_id uuid, active boolean, role text, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
    SELECT 
        a.id as agent_id,
        (SELECT n.name FROM agent_names an JOIN names n ON an.name_id = n.id WHERE an.agent_id = a.id LIMIT 1) as name,
        (SELECT d.description FROM agent_descriptions ad JOIN descriptions d ON ad.description_id = d.id WHERE ad.agent_id = a.id LIMIT 1) as description,
        (SELECT am.model_id FROM agent_models am WHERE am.agent_id = a.id LIMIT 1) as model_id,
        EXISTS (SELECT 1 FROM agent_flags af JOIN flags fl ON af.flag_id = fl.id WHERE af.agent_id = a.id AND fl.name = 'active' AND af.type = 'active'::type_agent_flags AND af.value = TRUE) as active,
        NULL::text as role,
        a.created_at,
        a.updated_at
    FROM agents a
    WHERE a.id = test_get_agent_by_id_v4.input_agent_id;
$$;


