--
-- Name: test_get_agent_prompt_link_status_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_agent_prompt_link_status_v4(input_agent_id uuid, input_prompt_id uuid) RETURNS TABLE(active boolean)
    LANGUAGE sql STABLE
    AS $$
    SELECT active
    FROM agent_prompts
    WHERE agent_id = input_agent_id
