--
-- Name: test_get_or_create_rubric_v4(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_or_create_rubric_v4() RETURNS TABLE(rubric_id uuid, name text, description text, points integer, pass_points integer, active boolean)
    LANGUAGE sql
    AS $$
    WITH name_resource AS (
        INSERT INTO names(name)
        VALUES ('Test Rubric')
        ON CONFLICT (name) DO NOTHING
        RETURNING id
    ),
    name_lookup AS (
        SELECT id FROM names WHERE name = 'Test Rubric' LIMIT 1
    ),
    description_resource AS (
        INSERT INTO descriptions(description)
        VALUES ('Test')
        ON CONFLICT (description) DO NOTHING
        RETURNING id
    ),
    description_lookup AS (
        SELECT id FROM descriptions WHERE description = 'Test' LIMIT 1
    ),
    points_resource AS (
        INSERT INTO points(value)
        VALUES (100)
        ON CONFLICT (value) DO NOTHING
        RETURNING id
    ),
    points_lookup AS (
        SELECT id FROM points WHERE value = 100 LIMIT 1
    ),
    pass_points_resource AS (
        INSERT INTO points(value)
        VALUES (70)
        ON CONFLICT (value) DO NOTHING
        RETURNING id
    ),
    pass_points_lookup AS (
        SELECT id FROM points WHERE value = 70 LIMIT 1
    ),
    active_flag AS (
        SELECT id FROM flags WHERE name = 'active' LIMIT 1
    ),
    existing_rubric AS (
        SELECT r.id, 
               (SELECT n.name FROM rubric_names rn JOIN names n ON rn.name_id = n.id WHERE rn.rubric_id = r.id LIMIT 1) as name,
               (SELECT d.description FROM rubric_descriptions rd JOIN descriptions d ON rd.description_id = d.id WHERE rd.rubric_id = r.id LIMIT 1) as description,
               (SELECT p.value FROM rubric_points rp JOIN points p ON rp.point_id = p.id WHERE rp.rubric_id = r.id AND rp.type = 'total'::type_rubric_points LIMIT 1) as points,
               (SELECT p.value FROM rubric_points rp JOIN points p ON rp.point_id = p.id WHERE rp.rubric_id = r.id AND rp.type = 'pass'::type_rubric_points LIMIT 1) as pass_points,
               EXISTS (SELECT 1 FROM rubric_flags rf JOIN flags fl ON rf.flag_id = fl.id WHERE rf.rubric_id = r.id AND fl.name = 'active' AND rf.type = 'active'::type_rubric_flags AND rf.value = TRUE) as active
        FROM rubrics r
        LIMIT 1
    ),
    new_rubric AS (
        INSERT INTO rubrics DEFAULT VALUES
        RETURNING id
    ),
    new_rubric_filtered AS (
        SELECT nr.id FROM new_rubric nr
        WHERE NOT EXISTS (SELECT 1 FROM existing_rubric)
    ),
    new_rubric_name_link AS (
        INSERT INTO rubric_names(rubric_id, name_id)
        SELECT nrf.id, COALESCE(nr3.id, nl.id)
        FROM new_rubric_filtered nrf, name_resource nr3 FULL OUTER JOIN name_lookup nl ON true
        RETURNING rubric_id
    ),
    new_rubric_description_link AS (
        INSERT INTO rubric_descriptions(rubric_id, description_id)
        SELECT nrf.id, COALESCE(dr.id, dl.id)
        FROM new_rubric_filtered nrf, description_resource dr FULL OUTER JOIN description_lookup dl ON true
        RETURNING rubric_id
    ),
    new_rubric_points_link AS (
        INSERT INTO rubric_points(rubric_id, point_id, type)
        SELECT nrf.id, COALESCE(pr.id, pl.id), 'total'::type_rubric_points
        FROM new_rubric_filtered nrf, points_resource pr FULL OUTER JOIN points_lookup pl ON true
        RETURNING rubric_id
    ),
    new_rubric_pass_points_link AS (
        INSERT INTO rubric_points(rubric_id, point_id, type)
        SELECT nrf.id, COALESCE(ppr.id, ppl.id), 'pass'::type_rubric_points
        FROM new_rubric_filtered nrf, pass_points_resource ppr FULL OUTER JOIN pass_points_lookup ppl ON true
        RETURNING rubric_id
    ),
    new_rubric_flag_link AS (
        INSERT INTO rubric_flags(rubric_id, flag_id, type, value)
        SELECT nrf.id, af.id, 'active'::type_rubric_flags, true
        FROM new_rubric_filtered nrf, active_flag af
        RETURNING rubric_id
    )
    SELECT 
        er.id as rubric_id, 
        er.name, 
        er.description, 
        er.points, 
        er.pass_points, 
        er.active
    FROM existing_rubric er
    UNION ALL
    SELECT 
        nrf.id as rubric_id,
        (SELECT n.name FROM rubric_names rn JOIN names n ON rn.name_id = n.id WHERE rn.rubric_id = nrf.id LIMIT 1) as name,
        (SELECT d.description FROM rubric_descriptions rd JOIN descriptions d ON rd.description_id = d.id WHERE rd.rubric_id = nrf.id LIMIT 1) as description,
        (SELECT p.value FROM rubric_points rp JOIN points p ON rp.point_id = p.id WHERE rp.rubric_id = nrf.id AND rp.type = 'total'::type_rubric_points LIMIT 1) as points,
        (SELECT p.value FROM rubric_points rp JOIN points p ON rp.point_id = p.id WHERE rp.rubric_id = nrf.id AND rp.type = 'pass'::type_rubric_points LIMIT 1) as pass_points,
        EXISTS (SELECT 1 FROM rubric_flags rf JOIN flags fl ON rf.flag_id = fl.id WHERE rf.rubric_id = nrf.id AND fl.name = 'active' AND rf.type = 'active'::type_rubric_flags AND rf.value = TRUE) as active
    FROM new_rubric_filtered nrf
    LIMIT 1;
$$;


--
-- Name: test_get_or_create_scenario_v4(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_or_create_scenario_v4() RETURNS TABLE(scenario_id uuid, name text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_scenario_id uuid;
BEGIN
    -- Try to get existing scenario
    SELECT id INTO v_scenario_id
    FROM scenarios
    LIMIT 1;

    -- If no scenario exists, create one
    IF v_scenario_id IS NULL THEN
        INSERT INTO scenarios(name, active)
        VALUES ('Test Scenario', true)
        RETURNING id INTO v_scenario_id;

        -- Insert self-referencing tree edge
        INSERT INTO scenario_tree(parent_id, child_id, active)
        VALUES (v_scenario_id, v_scenario_id, true);
    END IF;

    -- Return result
    RETURN QUERY
    SELECT 
        s.id as scenario_id,
        s.name
    FROM scenarios s
    WHERE s.id = v_scenario_id;
END;
$$;


--
-- Name: test_get_or_create_test_agent_v4(text, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_or_create_test_agent_v4(name text DEFAULT 'Test Agent'::text, description text DEFAULT 'Test Description'::text, model_id uuid DEFAULT NULL::uuid) RETURNS TABLE(agent_id uuid, name text, description text, model_id uuid)
    LANGUAGE sql
    AS $$
    WITH existing_agent AS (
        SELECT a.id, 
               (SELECT n.name FROM agent_names an JOIN names n ON an.name_id = n.id WHERE an.agent_id = a.id LIMIT 1) as name,
               (SELECT d.description FROM agent_descriptions ad JOIN descriptions d ON ad.description_id = d.id WHERE ad.agent_id = a.id LIMIT 1) as description,
               (SELECT am.model_id FROM agent_models am WHERE am.agent_id = a.id LIMIT 1) as model_id
        FROM agents a
        WHERE EXISTS (SELECT 1 FROM agent_flags af JOIN flags fl ON af.flag_id = fl.id WHERE af.agent_id = a.id AND fl.name = 'active' AND af.type = 'active'::type_agent_flags AND af.value = TRUE)
        LIMIT 1
    ),
    model_to_use AS (
        SELECT COALESCE(test_get_or_create_test_agent_v4.model_id, em.model_id) as id
        FROM existing_agent em
        WHERE test_get_or_create_test_agent_v4.model_id IS NOT NULL OR em.model_id IS NOT NULL
        LIMIT 1
    ),
    fallback_model AS (
        SELECT id FROM models m
        WHERE EXISTS (SELECT 1 FROM model_flags mf JOIN flags fl ON mf.flag_id = fl.id WHERE mf.model_id = m.id AND fl.name = 'active' AND mf.type = 'active'::type_model_flags AND mf.value = TRUE)
        LIMIT 1
    ),
    name_resource AS (
        INSERT INTO names(name)
        VALUES (test_get_or_create_test_agent_v4.name)
        ON CONFLICT (name) DO NOTHING
        RETURNING id
    ),
    name_lookup AS (
        SELECT id FROM names WHERE name = test_get_or_create_test_agent_v4.name LIMIT 1
    ),
    description_resource AS (
        INSERT INTO descriptions(description)
        VALUES (test_get_or_create_test_agent_v4.description)
        ON CONFLICT (description) DO NOTHING
        RETURNING id
    ),
    description_lookup AS (
        SELECT id FROM descriptions WHERE description = test_get_or_create_test_agent_v4.description LIMIT 1
    ),
    active_flag AS (
        SELECT id FROM flags WHERE name = 'active' LIMIT 1
    ),
    new_agent AS (
        INSERT INTO agents DEFAULT VALUES
        RETURNING id
    ),
    new_agent_filtered AS (
        SELECT na.id FROM new_agent na
        WHERE NOT EXISTS (SELECT 1 FROM existing_agent)
    ),
    new_agent_name_link AS (
        INSERT INTO agent_names(agent_id, name_id)
        SELECT naf.id, COALESCE(nr.id, nl.id)
        FROM new_agent_filtered naf, name_resource nr FULL OUTER JOIN name_lookup nl ON true
        RETURNING agent_id
    ),
    new_agent_description_link AS (
        INSERT INTO agent_descriptions(agent_id, description_id)
        SELECT naf.id, COALESCE(dr.id, dl.id)
        FROM new_agent_filtered naf, description_resource dr FULL OUTER JOIN description_lookup dl ON true
        RETURNING agent_id
    ),
    new_agent_model_link AS (
        INSERT INTO agent_models(agent_id, model_id)
        SELECT naf.id, COALESCE(mtu.id, fm.id)
        FROM new_agent_filtered naf, model_to_use mtu FULL OUTER JOIN fallback_model fm ON true
        RETURNING agent_id
    ),
    new_agent_flag_link AS (
        INSERT INTO agent_flags(agent_id, flag_id, type, value)
        SELECT naf.id, af.id, 'active'::type_agent_flags, true
        FROM new_agent_filtered naf, active_flag af
        RETURNING agent_id
    )
    SELECT 
        COALESCE(ea.id, naf.id) as agent_id,
        COALESCE(ea.name, (SELECT n.name FROM agent_names an JOIN names n ON an.name_id = n.id WHERE an.agent_id = naf.id LIMIT 1)) as name,
        COALESCE(ea.description, (SELECT d.description FROM agent_descriptions ad JOIN descriptions d ON ad.description_id = d.id WHERE ad.agent_id = naf.id LIMIT 1)) as description,
        COALESCE(ea.model_id, (SELECT am.model_id FROM agent_models am WHERE am.agent_id = naf.id LIMIT 1)) as model_id
    FROM existing_agent ea
    FULL OUTER JOIN new_agent_filtered naf ON true
    WHERE ea.id IS NOT NULL OR naf.id IS NOT NULL
    LIMIT 1;
$$;


--
-- Name: test_get_or_create_test_department_v4(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_or_create_test_department_v4(title text DEFAULT 'Computer Science'::text, description text DEFAULT 'Test Department Description'::text) RETURNS TABLE(department_id uuid, title text)
    LANGUAGE sql
    AS $$
    WITH name_resource AS (
        INSERT INTO names(name)
        VALUES (test_get_or_create_test_department_v4.title)
        ON CONFLICT (name) DO NOTHING
        RETURNING id
    ),
    name_lookup AS (
        SELECT id FROM names WHERE name = test_get_or_create_test_department_v4.title LIMIT 1
    ),
    description_resource AS (
        INSERT INTO descriptions(description)
        VALUES (test_get_or_create_test_department_v4.description)
        ON CONFLICT (description) DO NOTHING
        RETURNING id
    ),
    description_lookup AS (
        SELECT id FROM descriptions WHERE description = test_get_or_create_test_department_v4.description LIMIT 1
    ),
    active_flag AS (
        SELECT id FROM flags WHERE name = 'active' LIMIT 1
    ),
    existing_dept AS (
        SELECT d.id, (SELECT n.name FROM department_names dn JOIN names n ON dn.name_id = n.id WHERE dn.department_id = d.id LIMIT 1) as title
        FROM departments d
        WHERE (SELECT n.name FROM department_names dn JOIN names n ON dn.name_id = n.id WHERE dn.department_id = d.id LIMIT 1) = test_get_or_create_test_department_v4.title
        LIMIT 1
    ),
    new_dept AS (
        INSERT INTO departments DEFAULT VALUES
        RETURNING id
    ),
    new_dept_filtered AS (
        SELECT nd.id FROM new_dept nd
        WHERE NOT EXISTS (SELECT 1 FROM existing_dept)
    ),
    new_dept_name_link AS (
        INSERT INTO department_names(department_id, name_id)
        SELECT ndf.id, COALESCE(nr.id, nl.id)
        FROM new_dept_filtered ndf, name_resource nr FULL OUTER JOIN name_lookup nl ON true
        RETURNING department_id
    ),
    new_dept_description_link AS (
        INSERT INTO department_descriptions(department_id, description_id)
        SELECT ndf.id, COALESCE(dr.id, dl.id)
        FROM new_dept_filtered ndf, description_resource dr FULL OUTER JOIN description_lookup dl ON true
        RETURNING department_id
    ),
    new_dept_flag_link AS (
        INSERT INTO department_flags(department_id, flag_id, type, value)
        SELECT ndf.id, af.id, 'active'::type_department_flags, true
        FROM new_dept_filtered ndf, active_flag af
        RETURNING department_id
    )
    SELECT 
        COALESCE(ed.id, ndf.id) as department_id,
        COALESCE(ed.title, (SELECT n.name FROM department_names dn JOIN names n ON dn.name_id = n.id WHERE dn.department_id = ndf.id LIMIT 1)) as title
    FROM existing_dept ed
    FULL OUTER JOIN new_dept_filtered ndf ON true
    WHERE ed.id IS NOT NULL OR ndf.id IS NOT NULL
    LIMIT 1;
$$;


--
-- Name: test_get_or_create_test_model_v4(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_or_create_test_model_v4(name text DEFAULT 'Test Model'::text) RETURNS TABLE(model_id uuid, name text, provider_id uuid)
    LANGUAGE sql
    AS $$
    WITH existing_model AS (
        SELECT m.id, 
               (SELECT n.name FROM model_names mn JOIN names n ON mn.name_id = n.id WHERE mn.model_id = m.id LIMIT 1) as name,
               NULL::uuid as provider_id  -- Providers are now enums, not UUIDs
        FROM models m
        WHERE EXISTS (SELECT 1 FROM model_flags mf JOIN flags fl ON mf.flag_id = fl.id WHERE mf.model_id = m.id AND fl.name = 'active' AND mf.type = 'active'::type_model_flags AND mf.value = TRUE)
        LIMIT 1
    ),
    name_resource AS (
        INSERT INTO names(name)
        VALUES (test_get_or_create_test_model_v4.name)
        ON CONFLICT (name) DO NOTHING
        RETURNING id
    ),
    name_lookup AS (
        SELECT id FROM names WHERE name = test_get_or_create_test_model_v4.name LIMIT 1
    ),
    description_resource AS (
        INSERT INTO descriptions(description)
        VALUES ('Test Model Description')
        ON CONFLICT (description) DO NOTHING
        RETURNING id
    ),
    description_lookup AS (
        SELECT id FROM descriptions WHERE description = 'Test Model Description' LIMIT 1
    ),
    active_flag AS (
        SELECT id FROM flags WHERE name = 'active' LIMIT 1
    ),
    new_model AS (
        INSERT INTO models(value)
        SELECT 'gpt-4'
        WHERE NOT EXISTS (SELECT 1 FROM existing_model)
        RETURNING id
    ),
    new_model_name_link AS (
        INSERT INTO model_names(model_id, name_id)
        SELECT nm.id, COALESCE(nr.id, nl.id)
        FROM new_model nm, name_resource nr FULL OUTER JOIN name_lookup nl ON true
        WHERE NOT EXISTS (SELECT 1 FROM existing_model)
        RETURNING model_id
    ),
    new_model_description_link AS (
        INSERT INTO model_descriptions(model_id, description_id)
        SELECT nm.id, COALESCE(dr.id, dl.id)
        FROM new_model nm, description_resource dr FULL OUTER JOIN description_lookup dl ON true
        WHERE NOT EXISTS (SELECT 1 FROM existing_model)
        RETURNING model_id
    ),
    new_model_flag_link AS (
        INSERT INTO model_flags(model_id, flag_id, type, value)
        SELECT nm.id, af.id, 'active'::type_model_flags, true
        FROM new_model nm, active_flag af
        WHERE NOT EXISTS (SELECT 1 FROM existing_model)
        RETURNING model_id
    )
    SELECT 
        COALESCE(em.id, nm.id) as model_id,
        COALESCE(em.name, (SELECT n.name FROM model_names mn JOIN names n ON mn.name_id = n.id WHERE mn.model_id = nm.id LIMIT 1)) as name,
        NULL::uuid as provider_id  -- Providers are now enums, not UUIDs
    FROM existing_model em
    FULL OUTER JOIN new_model nm ON true
    WHERE em.id IS NOT NULL OR nm.id IS NOT NULL
    LIMIT 1;
$$;


--
-- Name: test_get_parameter_by_id_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_parameter_by_id_v4(input_parameter_id uuid) RETURNS TABLE(parameter_id uuid, name text, description text, active boolean, document_parameter boolean, simulation_parameter boolean, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
    SELECT 
        p.id AS parameter_id,
        (SELECT n.name FROM parameter_names pn JOIN names n ON pn.name_id = n.id WHERE pn.parameter_id = p.id LIMIT 1) AS name,
        (SELECT d.description FROM parameter_descriptions pd JOIN descriptions d ON pd.description_id = d.id WHERE pd.parameter_id = p.id LIMIT 1) AS description,
        EXISTS (SELECT 1 FROM parameter_flags pf JOIN flags fl ON pf.flag_id = fl.id WHERE pf.parameter_id = p.id AND fl.name = 'active' AND pf.type = 'active'::type_parameter_flags AND pf.value = TRUE) AS active,
        EXISTS (SELECT 1 FROM parameter_flags pf JOIN flags fl ON pf.flag_id = fl.id WHERE pf.parameter_id = p.id AND fl.name = 'document_parameter' AND pf.type = 'document_parameter'::type_parameter_flags AND pf.value = TRUE) AS document_parameter,
        EXISTS (SELECT 1 FROM parameter_flags pf JOIN flags fl ON pf.flag_id = fl.id WHERE pf.parameter_id = p.id AND fl.name = 'simulation_parameter' AND pf.type = 'simulation_parameter'::type_parameter_flags AND pf.value = TRUE) AS simulation_parameter,
        p.created_at,
        p.updated_at
    FROM parameters p
    WHERE p.id = input_parameter_id;
$$;


