        active,
        created_at
    FROM simulation_departments
    WHERE simulation_id = test_get_simulation_department_link_v4.input_simulation_id
      AND department_id = test_get_simulation_department_link_v4.input_department_id;
$$;


--
-- Name: test_get_simulation_scenario_link_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_simulation_scenario_link_v4(input_simulation_id uuid, input_scenario_id uuid) RETURNS TABLE(simulation_id uuid, scenario_id uuid, active boolean, "position" integer, created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
    SELECT 
        ss.simulation_id,
        ss.scenario_id,
        EXISTS (SELECT 1 FROM simulation_scenario_flags ssf WHERE ssf.simulation_id = ss.simulation_id AND ssf.scenario_id = ss.scenario_id AND ssf.type = 'active'::type_simulation_scenario_flags AND ssf.value = true) as active,
        COALESCE((SELECT sp.value FROM scenario_positions sp WHERE sp.simulation_id = ss.simulation_id AND sp.scenario_id = ss.scenario_id LIMIT 1), 999999) as "position",
        ss.created_at
    FROM simulation_scenarios ss
    WHERE ss.simulation_id = test_get_simulation_scenario_link_v4.input_simulation_id
      AND ss.scenario_id = test_get_simulation_scenario_link_v4.input_scenario_id;
$$;


--
-- Name: test_update_eval_use_groups_v4(uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_update_eval_use_groups_v4(eval_id uuid, use_groups boolean) RETURNS TABLE(eval_id uuid)
    LANGUAGE sql
    AS $$
    WITH groups_flag AS (
        SELECT id FROM flags WHERE name = 'groups' LIMIT 1
    )
    UPDATE eval_flags ef
    SET value = test_update_eval_use_groups_v4.use_groups
    FROM groups_flag gf
    WHERE ef.eval_id = test_update_eval_use_groups_v4.eval_id
      AND ef.flag_id = gf.id
      AND ef.type = 'groups'::type_eval_flags
    RETURNING ef.eval_id as eval_id;
$$;


