--
-- Name: utils_create_template_v4(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.utils_create_template_v4(template_id uuid, name text) RETURNS void
    LANGUAGE sql
    AS $_$
    INSERT INTO templates (id, name, created_at, updated_at)
    VALUES ($1, $2, NOW(), NOW())
$_$;


--
-- Name: utils_create_template_value_v4(uuid, uuid, text, numeric, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.utils_create_template_value_v4(template_id uuid, schema_field_id uuid, string_value text DEFAULT NULL::text, number_value numeric DEFAULT NULL::numeric, boolean_value boolean DEFAULT NULL::boolean) RETURNS void
    LANGUAGE plpgsql
    AS $_$
BEGIN
    INSERT INTO template_values (
        template_id, schema_field_id, string_value, number_value, boolean_value, created_at, updated_at
    )
    VALUES ($1, $2, $3, $4, $5, NOW(), NOW())
    ON CONFLICT (template_id, schema_field_id) DO UPDATE SET
        string_value = EXCLUDED.string_value,
        number_value = EXCLUDED.number_value,
        boolean_value = EXCLUDED.boolean_value,
        updated_at = NOW();
END;
$_$;


--
-- Name: utils_get_template_array_items_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.utils_get_template_array_items_v4(template_id uuid) RETURNS TABLE(name text, item_template_id uuid, "position" integer)
    LANGUAGE sql STABLE
    AS $_$
    SELECT sf.name, tai.item_template_id, tai."position"
    FROM template_array_items tai
    JOIN schema_fields sf ON sf.id = tai.schema_field_id
    WHERE tai.template_id = $1
    ORDER BY sf."position", tai."position"
$_$;


--
-- Name: utils_get_template_values_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.utils_get_template_values_v4(template_id uuid) RETURNS TABLE(name text, string_value text, number_value numeric, boolean_value boolean, field_type text)
    LANGUAGE sql STABLE
    AS $_$
    SELECT sf.name, tv.string_value, tv.number_value, tv.boolean_value, sf.field_type
    FROM template_values tv
    JOIN schema_fields sf ON sf.id = tv.schema_field_id
    WHERE tv.template_id = $1
    ORDER BY sf.position
$_$;


--
-- Name: utils_link_schema_template_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.utils_link_schema_template_v4(schema_id uuid, template_id uuid) RETURNS void
    LANGUAGE sql
    AS $_$
    INSERT INTO schema_templates (schema_id, template_id, created_at, updated_at)
    VALUES ($1, $2, NOW(), NOW())
    ON CONFLICT (schema_id, template_id) DO UPDATE SET updated_at = NOW()
$_$;


--
-- Name: validate_department_create_permissions(text, text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_department_create_permissions(p_user_role text, p_department_ids text[]) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Non-superadmins cannot create general objects (empty department_ids)
    IF p_user_role != 'superadmin' AND COALESCE(array_length(p_department_ids, 1), 0) = 0 THEN
        RAISE EXCEPTION 'DEPARTMENT_PERMISSION_DENIED: Non-superadmins cannot create general objects';
    END IF;
    RETURN TRUE;
END;
$$;


--
-- Name: validate_department_update_permissions(text, text[], text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_department_update_permissions(p_user_role text, p_object_department_ids text[], p_user_department_ids text[]) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Non-superadmins cannot modify general objects (no department links)
    IF p_user_role != 'superadmin' AND COALESCE(array_length(p_object_department_ids, 1), 0) = 0 THEN
        RAISE EXCEPTION 'DEPARTMENT_PERMISSION_DENIED: Non-superadmins cannot modify general objects';
    END IF;
    
    -- Non-superadmins must belong to ALL object's departments
    IF p_user_role != 'superadmin' AND COALESCE(array_length(p_object_department_ids, 1), 0) > 0 THEN
        IF NOT (
            SELECT bool_and(dept_id = ANY(p_user_department_ids))
            FROM UNNEST(p_object_department_ids) as dept_id
        ) THEN
            RAISE EXCEPTION 'DEPARTMENT_PERMISSION_DENIED: User must belong to all departments of this object to modify it';
        END IF;
    END IF;
    
    RETURN TRUE;
END;
$$;


--
-- Name: validate_rate_limit(integer, bigint); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_rate_limit(p_req_per_day integer, p_runs_today_count bigint) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF p_req_per_day IS NOT NULL AND p_runs_today_count >= p_req_per_day THEN
        RAISE EXCEPTION 'RATE_LIMIT_EXCEEDED: Daily request limit of % reached. Please try again tomorrow.', p_req_per_day;
    END IF;
    RETURN TRUE;
END;
$$;


